#[allow(clippy::too_many_arguments)]
fn select_block_sync_roster(
    block: &SignedBlock,
    block_hash: HashOf<BlockHeader>,
    block_height: u64,
    persisted: Option<BlockSyncRosterSelection>,
    cert_hint: Option<&Qc>,
    checkpoint_hint: Option<&ValidatorSetCheckpoint>,
    state: &State,
    trusted: &iroha_config::parameters::actual::TrustedPeers,
    local_peer: &PeerId,
    mode_tag: &'static str,
    allow_uncertified: bool,
) -> Option<BlockSyncRosterSelection> {
    let roster_cache = roster_cache_for_state(state, EPOCH_LENGTH_BLOCKS);
    super::select_block_sync_roster(
        block,
        block_hash,
        block_height,
        persisted,
        cert_hint,
        checkpoint_hint,
        None,
        state,
        trusted,
        local_peer,
        ConsensusMode::Permissioned,
        mode_tag,
        allow_uncertified,
        &roster_cache,
    )
}

fn roster_cache_for_state(
    state: &State,
    fallback_epoch_length: u64,
) -> super::RosterValidationCache {
    let world = state.world.view();
    let cache = super::RosterValidationCache::from_world(&world, fallback_epoch_length, None);
    drop(world);
    cache
}

fn sample_chunk_with_len(idx: u32, len: usize) -> crate::sumeragi::consensus::RbcChunk {
    let idx_byte = u8::try_from(idx).expect("idx fits in u8 for test chunk");
    crate::sumeragi::consensus::RbcChunk {
        block_hash: HashOf::from_untyped_unchecked(Hash::prehashed([idx_byte; Hash::LENGTH])),
        height: 1,
        view: 1,
        idx,
        epoch: 0,
        bytes: vec![0u8; len],
    }
}

fn roster_hash(roster: &[PeerId]) -> Hash {
    Hash::new(&roster.to_vec().encode())
}

fn signature_sender_index(
    actor: &Actor,
    roster: &[PeerId],
    height: u64,
    view: u64,
    signer_peer: &PeerId,
) -> u32 {
    let topology = super::network_topology::Topology::new(roster.to_vec());
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let signature_topology = super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
    let idx = signature_topology
        .as_ref()
        .iter()
        .position(|peer| peer == signer_peer)
        .expect("signer peer in topology");
    u32::try_from(idx).expect("signer index fits u32")
}

fn attach_background_log(
    actor: &mut Actor,
) -> Arc<Mutex<Vec<super::BackgroundRequestLogEntry>>> {
    let log = Arc::new(Mutex::new(Vec::new()));
    actor.background_request_log = Some(Arc::clone(&log));
    log
}

fn take_background_log(
    log: &Arc<Mutex<Vec<super::BackgroundRequestLogEntry>>>,
) -> Vec<super::BackgroundRequestLogEntry> {
    let mut guard = log.lock().expect("background request log mutex poisoned");
    std::mem::take(&mut *guard)
}

