#[tokio::test(flavor = "current_thread")]
async fn block_sync_update_known_block_reuses_commit_roster_snapshot() {
    super::status::reset_block_sync_counters_for_tests();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let block_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let height = 1_u64;
    let view = 0_u64;
    let epoch = actor.epoch_for_height(height);
    let roster = actor.effective_commit_topology();
    assert!(!roster.is_empty(), "test requires commit roster");
    let topology = super::network_topology::Topology::new(roster.clone());
    let required = topology.min_votes_for_commit().max(1);
    let mut signers = BTreeSet::new();
    for idx in 0..topology.as_ref().len() {
        if signers.len() >= required {
            break;
        }
        signers.insert(
            ValidatorIndex::try_from(u32::try_from(idx).expect("signer idx fits"))
                .expect("signer idx fits"),
        );
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, topology.as_ref().len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        qc.parent_state_root,
        qc.post_state_root,
        roster,
        signers_bitmap,
        qc.aggregate.bls_aggregate_signature.clone(),
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut journal = state.commit_roster_journal.write();
        journal.upsert(qc.clone(), checkpoint.clone(), None);
    }

    let block = actor
        .kura
        .get_block(NonZeroUsize::new(1).expect("height"))
        .expect("block exists");
    let mut update = super::message::BlockSyncUpdate::from(block.as_ref());
    update.commit_qc = Some(qc.clone());
    update.validator_checkpoint = Some(checkpoint);
    update.stake_snapshot = None;
    update.commit_votes.clear();

    let tally_signers = signers_from_bitmap(&qc.aggregate.signers_bitmap, topology.as_ref().len());
    actor.qc_signer_tally.insert(
        Actor::qc_tally_key(&qc),
        super::QcSignerTally {
            voting_signers: tally_signers.clone(),
            present_signers: tally_signers.len(),
        },
    );
    actor.roster_validation_cache.pops.clear();

    let before = super::status::snapshot()
        .block_sync_roster
        .drop_missing_total;
    actor
        .handle_block_sync_update(update, None)
        .expect("block sync update");
    let after = super::status::snapshot()
        .block_sync_roster
        .drop_missing_total;
    assert_eq!(
        after, before,
        "known blocks should reuse commit roster snapshots"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn block_sync_update_known_block_revalidates_qc_on_hash_mismatch() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let block_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let height = 1_u64;
    let view = 0_u64;
    let epoch = actor.epoch_for_height(height);
    let roster = actor.effective_commit_topology();
    assert!(!roster.is_empty(), "test requires commit roster");
    let topology = super::network_topology::Topology::new(roster.clone());
    let required = topology.min_votes_for_commit().max(1);
    let mut signers = BTreeSet::new();
    for idx in 0..topology.as_ref().len() {
        if signers.len() >= required {
            break;
        }
        signers.insert(
            ValidatorIndex::try_from(u32::try_from(idx).expect("signer idx fits"))
                .expect("signer idx fits"),
        );
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, topology.as_ref().len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    actor
        .qc_cache
        .insert((Phase::Commit, block_hash, height, view, epoch), qc.clone());
    actor.note_validated_qc_tally(
        &qc,
        QcSignerTally {
            voting_signers: signers.clone(),
            present_signers: signers.len(),
        },
    );

    let mut qc_invalid = qc.clone();
    if let Some(byte) = qc_invalid.aggregate.bls_aggregate_signature.first_mut() {
        *byte ^= 0xFF;
    } else {
        qc_invalid.aggregate.bls_aggregate_signature.push(0xFF);
    }
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        qc.parent_state_root,
        qc.post_state_root,
        roster,
        signers_bitmap,
        qc.aggregate.bls_aggregate_signature.clone(),
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );

    let block = actor
        .kura
        .get_block(NonZeroUsize::new(1).expect("height"))
        .expect("block exists");
    let roster_cache =
        roster_cache_for_state(actor.state.as_ref(), actor.config.npos.epoch_length_blocks);
    let mut update = super::block_sync_update_with_roster(
        block.as_ref(),
        actor.state.as_ref(),
        actor.kura.as_ref(),
        ConsensusMode::Permissioned,
        actor.common_config.trusted_peers.value(),
        actor.common_config.peer.id(),
        &roster_cache,
    );
    update.commit_qc = Some(qc_invalid);
    update.validator_checkpoint = Some(checkpoint);
    update.stake_snapshot = None;
    update.commit_votes.clear();

    actor
        .handle_block_sync_update(update, None)
        .expect("block sync update");
    drain_known_block_qc_work(actor);

    let cached = actor
        .qc_cache
        .get(&(Phase::Commit, block_hash, height, view, epoch))
        .expect("qc cached");
    assert_eq!(
        HashOf::new(cached),
        HashOf::new(&qc),
        "mismatched QC must not replace cached entry"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn block_sync_update_known_block_accepts_quorum_qc_on_hash_mismatch() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let block_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let height = 1_u64;
    let view = 0_u64;
    let epoch = actor.epoch_for_height(height);
    let roster = actor.effective_commit_topology();
    assert!(!roster.is_empty(), "test requires commit roster");
    let topology = super::network_topology::Topology::new(roster.clone());
    let required = topology.min_votes_for_commit().max(1);
    assert!(required > 1, "test requires commit quorum > 1");

    let mut partial_signers = BTreeSet::new();
    for idx in 0..topology.as_ref().len() {
        let needed = required.saturating_sub(1).max(1);
        if partial_signers.len() >= needed {
            break;
        }
        partial_signers.insert(
            ValidatorIndex::try_from(u32::try_from(idx).expect("signer idx fits"))
                .expect("signer idx fits"),
        );
    }
    let partial_bitmap = super::build_signers_bitmap(&partial_signers, topology.as_ref().len());
    let qc_partial = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        partial_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint_partial = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        qc_partial.parent_state_root,
        qc_partial.post_state_root,
        roster.clone(),
        partial_bitmap,
        qc_partial.aggregate.bls_aggregate_signature.clone(),
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut journal = state.commit_roster_journal.write();
        journal.upsert(qc_partial.clone(), checkpoint_partial.clone(), None);
    }
    let snapshot_before = actor
        .state
        .commit_roster_snapshot_for_block(height, block_hash)
        .expect("commit roster snapshot recorded");
    assert_eq!(
        HashOf::new(&snapshot_before.commit_qc),
        HashOf::new(&qc_partial),
        "test requires local snapshot to use partial QC"
    );

    let mut full_signers = BTreeSet::new();
    for idx in 0..topology.as_ref().len() {
        if full_signers.len() >= required {
            break;
        }
        full_signers.insert(
            ValidatorIndex::try_from(u32::try_from(idx).expect("signer idx fits"))
                .expect("signer idx fits"),
        );
    }
    let full_bitmap = super::build_signers_bitmap(&full_signers, topology.as_ref().len());
    let qc_full = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        view,
        epoch,
        full_bitmap.clone(),
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    assert_ne!(
        HashOf::new(&qc_partial),
        HashOf::new(&qc_full),
        "test requires mismatched QC hashes"
    );
    let checkpoint_full = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        qc_full.parent_state_root,
        qc_full.post_state_root,
        roster,
        full_bitmap,
        qc_full.aggregate.bls_aggregate_signature.clone(),
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );

    let block = actor
        .kura
        .get_block(NonZeroUsize::new(1).expect("height"))
        .expect("block exists");
    let roster_cache =
        roster_cache_for_state(actor.state.as_ref(), actor.config.npos.epoch_length_blocks);
    let mut update = super::block_sync_update_with_roster(
        block.as_ref(),
        actor.state.as_ref(),
        actor.kura.as_ref(),
        ConsensusMode::Permissioned,
        actor.common_config.trusted_peers.value(),
        actor.common_config.peer.id(),
        &roster_cache,
    );
    update.commit_qc = Some(qc_full.clone());
    update.validator_checkpoint = Some(checkpoint_full);
    update.stake_snapshot = None;
    update.commit_votes.clear();

    actor
        .handle_block_sync_update(update, None)
        .expect("block sync update");
    drain_known_block_qc_work(actor);

    let view = actor.state.view();
    let stored = view
        .world()
        .commit_qcs()
        .get(&block_hash)
        .expect("commit certificate recorded");
    assert_eq!(
        HashOf::new(stored),
        HashOf::new(&qc_full),
        "quorum QC should replace cached commit certificate"
    );

    harness.shutdown.send();
}

