#[test]
fn cached_qc_for_filters_epoch() {
    let chain: ChainId = "cached-qc-epoch".parse().expect("chain id parses");
    let keypair = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let peer_id = PeerId::new(keypair.public_key().clone());
    let topology = super::network_topology::Topology::new(vec![peer_id]);
    let keypairs = vec![keypair];
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xA1; Hash::LENGTH]));
    let height = 5;
    let view = 0;
    let signers_bitmap = vec![0b0000_0001];
    let qc_epoch0 = qc_with_bitmap(
        &chain,
        block_hash,
        height,
        view,
        0,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &keypairs,
    );
    let qc_epoch1 = qc_with_bitmap(
        &chain,
        block_hash,
        height,
        view,
        1,
        signers_bitmap.clone(),
        Phase::Commit,
        &topology,
        &keypairs,
    );
    let mut qc_cache = BTreeMap::new();
    qc_cache.insert(
        (Phase::Commit, block_hash, height, view, 0),
        qc_epoch0.clone(),
    );
    qc_cache.insert(
        (Phase::Commit, block_hash, height, view, 1),
        qc_epoch1.clone(),
    );

    let cached_epoch0 = super::cached_qc_for(&qc_cache, Phase::Commit, block_hash, height, view, 0)
        .expect("epoch 0 qc cached");
    assert_eq!(cached_epoch0.epoch, 0);
    assert_eq!(
        cached_epoch0.aggregate.bls_aggregate_signature,
        qc_epoch0.aggregate.bls_aggregate_signature
    );

    let cached_epoch1 = super::cached_qc_for(&qc_cache, Phase::Commit, block_hash, height, view, 1)
        .expect("epoch 1 qc cached");
    assert_eq!(cached_epoch1.epoch, 1);
    assert_eq!(
        cached_epoch1.aggregate.bls_aggregate_signature,
        qc_epoch1.aggregate.bls_aggregate_signature
    );

    assert!(super::cached_qc_for(&qc_cache, Phase::Commit, block_hash, height, view, 2).is_none());
}

#[tokio::test(flavor = "current_thread")]
async fn block_sync_update_allows_nonextending_qc_without_commit_qc() {
    use crate::sumeragi::status;

    status::reset_commit_certs_for_tests();
    status::reset_validator_checkpoints_for_tests();
    let _guard = status::qc_status_test_guard();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let roster = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(roster.clone());
    let parent_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xAA; 32]));
    let (locked_block, candidate_block) = {
        let signed_block = |height: u64, view: u64, parent: Option<HashOf<BlockHeader>>| {
            let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
            let signature_topology =
                super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
            let signer_peer = signature_topology
                .as_ref()
                .first()
                .expect("commit topology not empty");
            let signer_kp = harness
                .key_pairs
                .iter()
                .find(|kp| kp.public_key() == signer_peer.public_key())
                .expect("signer keypair exists in harness");
            let signer_idx = signature_topology
                .position(signer_kp.public_key())
                .expect("signer index in topology");
            heartbeat_block_for_state(
                actor.state.as_ref(),
                &actor.common_config.chain,
                height,
                view,
                parent,
                signer_kp,
                u64::try_from(signer_idx).expect("signer index fits u64"),
            )
        };

        (
            signed_block(1, 0, None),
            signed_block(2, 1, Some(parent_hash)),
        )
    };
    actor
        .kura
        .store_block(locked_block.clone())
        .expect("store locked block");
    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    state.push_block_hash_for_testing(locked_block.hash());
    let locked_pending = PendingBlock::new(locked_block.clone(), Hash::prehashed([0x21; 32]), 1, 0);
    actor
        .pending
        .pending_blocks
        .insert(locked_block.hash(), locked_pending);
    let candidate_height = candidate_block.header().height().get();
    let candidate_view = candidate_block.header().view_change_index();
    let candidate_payload = super::proposals::block_payload_bytes(&candidate_block);
    let candidate_payload_hash = Hash::new(&candidate_payload);
    let candidate_pending = PendingBlock::new(
        candidate_block.clone(),
        candidate_payload_hash,
        candidate_height,
        candidate_view,
    );
    actor
        .pending
        .pending_blocks
        .insert(candidate_block.hash(), candidate_pending);

    actor.locked_qc = Some(QcHeaderRef {
        phase: Phase::Commit,
        subject_block_hash: locked_block.hash(),
        height: 1,
        view: 0,
        epoch: 0,
    });
    super::status::set_locked_qc(1, 0, Some(locked_block.hash()));

    let chain = actor.common_config.chain.clone();
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(2);
    let qc_topology = super::topology_for_view(&topology, 2, 1, mode_tag, prf_seed);
    let qc = qc_with_view_bitmap(
        &chain,
        candidate_block.hash(),
        2,
        1,
        0,
        &[0b0000_1111],
        Phase::Commit,
        &qc_topology,
        &topology,
        &harness.key_pairs,
    );
    let state_view = actor.state.view();
    let block_signers = super::validated_block_signers(
        &candidate_block,
        &topology,
        &state_view,
        mode_tag,
        prf_seed,
    )
    .expect("block signatures valid for block sync");
    drop(state_view);
    let world = world_with_consensus_keys(topology.as_ref(), &harness.key_pairs);
    let world_view = world.view();
    let inputs = roster_validation_inputs_for_view(
        &world_view,
        topology.as_ref(),
        ConsensusMode::Permissioned,
        None,
    );
    super::validate_block_sync_qc(
        &qc,
        &topology,
        &world_view,
        &block_signers,
        candidate_block.header().view_change_index(),
        &inputs.pops,
        &chain,
        ConsensusMode::Permissioned,
        None,
        mode_tag,
        prf_seed,
        None,
    )
    .expect("block sync QC should validate");
    let signatures = super::canonicalize_block_signatures_for_roster(
        &candidate_block,
        &roster,
        mode_tag,
        prf_seed,
    );
    let checkpoint_signers: BTreeSet<_> = signatures
        .iter()
        .filter_map(|sig| ValidatorIndex::try_from(sig.index()).ok())
        .collect();
    let checkpoint_bitmap = super::build_signers_bitmap(&checkpoint_signers, roster.len());
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &chain,
        mode_tag,
        candidate_block.hash(),
        2,
        1,
        0,
        &checkpoint_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let checkpoint = ValidatorSetCheckpoint::new(
        2,
        candidate_block.header().view_change_index(),
        candidate_block.hash(),
        zero_state_root(),
        zero_state_root(),
        roster.clone(),
        checkpoint_bitmap,
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    let mut update = super::message::BlockSyncUpdate::from(&candidate_block);
    update.validator_checkpoint = Some(checkpoint);
    update.commit_qc = Some(qc);
    actor
        .handle_block_sync_update(update, None)
        .expect("block sync update");
    assert!(
        actor
            .qc_cache
            .contains_key(&(Phase::Commit, candidate_block.hash(), 2, 1, 0)),
        "non-extending commit certificate should be cached"
    );
    let locked = actor.locked_qc.expect("locked qc updated");
    assert_eq!(locked.subject_block_hash, candidate_block.hash());

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn fetch_pending_block_attaches_cached_qc() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let block = nonempty_block_for_actor(actor, &harness.key_pairs, 2, 0, None);
    let block_hash = block.hash();
    actor.kura.store_block(block.clone()).expect("store block");

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let signers: BTreeSet<_> = [0_u32, 1_u32, 2_u32].into_iter().collect();
    let signers_bitmap = vec![0b0000_0111];
    let aggregate_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        block.header().height().get(),
        block.header().view_change_index(),
        0,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let validator_set = topology.as_ref().to_vec();

    crate::sumeragi::status::record_precommit_signers(
        crate::sumeragi::status::PrecommitSignerRecord {
            block_hash,
            height: block.header().height().get(),
            view: block.header().view_change_index(),
            epoch: 0,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            signers,
            bls_aggregate_signature: aggregate_signature.clone(),
            roster_len: topology.as_ref().len(),
            mode_tag: PERMISSIONED_TAG.to_string(),
            validator_set,
            stake_snapshot: None,
        },
    );

    let request = super::message::FetchPendingBlock {
        requester: actor.common_config.peer.id.clone(),
        block_hash,
        height: block.header().height().get(),
        view: block.header().view_change_index(),
        priority: None,
    };
    let _ = harness.background_rx.try_iter().count();
    actor
        .handle_fetch_pending_block(request)
        .expect("fetch pending block");

    // FetchPendingBlock responses are enqueued on the background queue.
    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    let mut found = false;
    for post in posts {
        if let BackgroundPost::Post {
            msg: BlockMessage::BlockSyncUpdate(update),
            ..
        } = post
        {
            if update.block.hash() == block_hash {
                let qc = update
                    .commit_qc
                    .expect("cached commit certificate should be attached");
                assert_eq!(qc.height, block.header().height().get());
                assert_eq!(qc.view, block.header().view_change_index());
                assert_eq!(qc.aggregate.signers_bitmap, signers_bitmap);
                assert_eq!(qc.aggregate.bls_aggregate_signature, aggregate_signature);
                found = true;
            }
        }
    }
    assert!(found, "expected block sync update response");

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn fetch_pending_block_uses_block_sync_update_when_roster_available() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let genesis_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let height = 2u64;
    let view = 0u64;
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(height);
    let signature_topology = super::topology_for_view(&topology, height, view, mode_tag, prf_seed);
    let signer_peer = signature_topology
        .as_ref()
        .first()
        .expect("commit topology not empty");
    let signer_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == signer_peer.public_key())
        .expect("signer keypair exists in harness");
    let signer_idx = signature_topology
        .position(signer_kp.public_key())
        .expect("signer index in topology");
    let block = heartbeat_block_for_state(
        actor.state.as_ref(),
        &actor.common_config.chain,
        height,
        view,
        Some(genesis_hash),
        signer_kp,
        u64::try_from(signer_idx).expect("signer index fits u64"),
    );
    let block_hash = block.hash();
    let payload_hash = Hash::prehashed([0x44; 32]);
    let pending = PendingBlock::new(block.clone(), payload_hash, height, view);
    actor.pending.pending_blocks.insert(block_hash, pending);
    let commit_topology = actor.effective_commit_topology();
    {
        let mut block = actor.state.commit_topology.block();
        let mut tx = block.transaction();
        *tx = commit_topology;
        tx.apply();
        block.commit();
    }
    let signers: BTreeSet<ValidatorIndex> = (0..signature_topology.as_ref().len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, signature_topology.as_ref().len());
    let aggregate_signature = aggregate_vote_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        block_hash,
        height,
        view,
        0,
        &signers_bitmap,
        &signature_topology,
        &harness.key_pairs,
    );
    crate::sumeragi::status::record_precommit_signers(
        crate::sumeragi::status::PrecommitSignerRecord {
            block_hash,
            height,
            view,
            epoch: 0,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            signers: signers.clone(),
            bls_aggregate_signature: aggregate_signature.clone(),
            roster_len: signature_topology.as_ref().len(),
            mode_tag: PERMISSIONED_TAG.to_string(),
            validator_set: signature_topology.as_ref().to_vec(),
            stake_snapshot: None,
        },
    );
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        zero_state_root(),
        zero_state_root(),
        signature_topology.as_ref().to_vec(),
        signers_bitmap,
        aggregate_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    super::status::record_validator_checkpoint(checkpoint);

    let request = super::message::FetchPendingBlock {
        requester: actor.common_config.peer.id.clone(),
        block_hash,
        height,
        view,
        priority: Some(super::message::FetchPendingBlockPriority::Consensus),
    };
    let block_created = BlockMessage::BlockCreated(super::message::BlockCreated::from(&block));
    let block_created_len =
        super::consensus_block_wire_len(actor.common_config.peer.id(), &block_created);
    if actor.consensus_payload_frame_cap < block_created_len {
        actor.consensus_payload_frame_cap = block_created_len;
    }
    let _ = harness.background_rx.try_iter().count();
    actor
        .handle_fetch_pending_block(request)
        .expect("fetch pending block");

    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    let mut found = false;
    let mut found_created = false;
    for post in posts {
        if let BackgroundPost::Post {
            msg: BlockMessage::BlockSyncUpdate(update),
            ..
        } = &post
        {
            if update.block.hash() == block_hash {
                assert!(
                    update.commit_qc.is_some() || update.validator_checkpoint.is_some(),
                    "expected roster hints for pending block"
                );
                found = true;
            }
        }
        if let BackgroundPost::Post {
            msg: BlockMessage::BlockCreated(created),
            ..
        } = &post
        {
            if created.block.hash() == block_hash {
                found_created = true;
            }
        }
    }
    assert!(
        found,
        "expected block sync update response for pending block"
    );
    assert!(
        found_created,
        "expected BlockCreated response for pending block"
    );

    harness.shutdown.send();
}

