#[tokio::test(flavor = "current_thread")]
async fn commit_vote_quorum_uses_cached_roster_after_topology_reorder() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let local_peer = actor.common_config.peer.id().clone();
    let mut peers: Vec<PeerId> = harness
        .key_pairs
        .iter()
        .map(|keypair| PeerId::new(keypair.public_key().clone()))
        .collect();
    peers.retain(|peer| peer != &local_peer);

    let mut initial_topology = Vec::with_capacity(peers.len() + 1);
    initial_topology.push(peers[0].clone());
    initial_topology.push(local_peer.clone());
    initial_topology.extend(peers[1..].iter().cloned());

    let mut topo_cell = actor.state.commit_topology.block();
    topo_cell.clear();
    topo_cell.extend(initial_topology.clone());
    topo_cell.commit();

    let tx = sample_transaction();
    let block = block_with_txs(1, 0, None, vec![tx]);
    let block_hash = block.hash();
    let height = block.header().height().get();
    let view = block.header().view_change_index();
    let parent_hash = block.header().prev_block_hash();
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());

    let epoch = actor.epoch_for_height(height);
    assert!(
        actor.emit_precommit_vote(
            block_hash,
            height,
            view,
            epoch,
            &topology,
            parent_hash,
            Some((Hash::new([]), Hash::new([]))),
        ),
        "commit vote should be recorded"
    );

    let mut reordered = Vec::with_capacity(peers.len() + 1);
    reordered.push(local_peer.clone());
    reordered.extend(peers.iter().cloned());
    let mut topo_cell = actor.state.commit_topology.block();
    topo_cell.clear();
    topo_cell.extend(reordered);
    topo_cell.commit();

    let (vote_count, _quorum_reached) =
        actor.commit_vote_quorum_status_for_block(block_hash, height, view);
    assert_eq!(
        vote_count, 1,
        "cached roster should keep the local vote valid after reordering"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn quorum_reschedule_keeps_cached_commit_qc_on_drop() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let view = actor.state.view();
    let height = view.height() as u64 + 1;
    let parent = view.latest_block_hash();
    drop(view);

    let block = sample_block(height, 0, parent);
    let block_hash = block.hash();
    let payload_bytes = super::proposals::block_payload_bytes(&block);
    // Use a mismatched payload hash to force missing-local-data gating in DA mode.
    let mut payload_hash_bytes: [u8; Hash::LENGTH] = Hash::new(&payload_bytes).into();
    payload_hash_bytes[0] ^= 0xFF;
    let payload_hash = Hash::prehashed(payload_hash_bytes);
    let mut pending = PendingBlock::new(block, payload_hash, height, 0);
    pending.last_quorum_reschedule = Some(Instant::now());

    let commit_topology = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(commit_topology.clone());
    let epoch = actor.epoch_for_height(height);
    let signers: BTreeSet<ValidatorIndex> = (0..commit_topology.len())
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index fits"))
        .collect();
    let signers_bitmap = super::build_signers_bitmap(&signers, commit_topology.len());
    let qc = qc_with_bitmap(
        &actor.common_config.chain,
        block_hash,
        height,
        0,
        epoch,
        signers_bitmap,
        Phase::Commit,
        &topology,
        &harness.key_pairs,
    );
    let qc_key = (Phase::Commit, block_hash, height, 0, epoch);
    actor.qc_cache.insert(qc_key, qc);
    actor.qc_signer_tally.insert(
        qc_key,
        super::QcSignerTally {
            voting_signers: signers,
            present_signers: commit_topology.len(),
        },
    );

    actor.reschedule_pending_quorum_block(
        pending,
        Duration::from_secs(5),
        topology.min_votes_for_commit(),
        /*vote_count*/ 0,
        /*quorum_timeout*/ Duration::from_secs(1),
        /*reschedule_backoff*/ Duration::from_secs(1),
        Instant::now(),
    );

    let retained = actor
        .pending
        .pending_blocks
        .get(&block_hash)
        .is_some_and(|pending| pending.aborted);
    assert!(
        retained,
        "pending payload should be retained as aborted after reschedule drop"
    );
    assert!(
        actor.qc_cache.contains_key(&qc_key),
        "cached commit QC should survive reschedule drop"
    );
    assert!(
        actor.qc_signer_tally.contains_key(&qc_key),
        "cached commit QC signer tally should be retained"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn payload_rebroadcast_targets_only_highest_pending_block() {
    let mut harness = test_actor_harness(4).await;
    harness.actor.config.rbc.rebroadcast_sessions_per_tick = 1;
    let view = harness.actor.state.view();
    let tip_height = view.height();
    let tip_hash = view.latest_block_hash();
    drop(view);
    let next_height = u64::try_from(tip_height.saturating_add(1)).unwrap_or(u64::MAX);
    let low = sample_block(next_height, 0, tip_hash);
    let high = sample_block(next_height, 1, tip_hash);
    let low_hash = low.hash();
    let high_hash = high.hash();
    let roster = harness.actor.effective_commit_topology();
    assert!(!roster.is_empty(), "roster should not be empty");

    let low_payload = super::proposals::block_payload_bytes(&low);
    let low_payload_hash = Hash::new(&low_payload);
    let mut low_pending = PendingBlock::new(low.clone(), low_payload_hash, next_height, 0);
    low_pending.validation_status = ValidationStatus::Valid;
    harness
        .actor
        .pending
        .pending_blocks
        .insert(low_hash, low_pending);

    let high_payload = super::proposals::block_payload_bytes(&high);
    let high_payload_hash = Hash::new(&high_payload);
    let mut high_pending = PendingBlock::new(high.clone(), high_payload_hash, next_height, 1);
    high_pending.validation_status = ValidationStatus::Valid;
    harness
        .actor
        .pending
        .pending_blocks
        .insert(high_hash, high_pending);

    let epoch = harness.actor.epoch_for_height(next_height);
    let mut low_session =
        Actor::build_rbc_session_from_payload(&low_payload, low_payload_hash, 1024, epoch)
            .expect("low rbc session");
    let low_header = low.header();
    low_session.block_header = Some(low_header.clone());
    low_session.leader_signature = Some(leader_signature_for_header(
        &harness.actor,
        &roster,
        &low_header,
        &harness.key_pairs,
    ));
    let low_key = Actor::session_key(&low_hash, next_height, 0);
    harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(low_key, low_session);

    let mut high_session =
        Actor::build_rbc_session_from_payload(&high_payload, high_payload_hash, 1024, epoch)
            .expect("high rbc session");
    let high_header = high.header();
    high_session.block_header = Some(high_header.clone());
    high_session.leader_signature = Some(leader_signature_for_header(
        &harness.actor,
        &roster,
        &high_header,
        &harness.key_pairs,
    ));
    let high_key = Actor::session_key(&high_hash, next_height, 1);
    harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(high_key, high_session);

    harness.actor.record_rbc_session_roster(
        low_key,
        roster.clone(),
        super::RbcRosterSource::Derived,
    );
    harness.actor.record_rbc_session_roster(
        high_key,
        roster.clone(),
        super::RbcRosterSource::Derived,
    );
    harness.actor.subsystems.da_rbc.rbc.rebroadcast_cursor = Some(low_key);
    harness
        .actor
        .rebroadcast_stalled_rbc_payloads(Instant::now());

    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    let has_payload_posts = posts.iter().any(|post| {
        matches!(
            post,
            BackgroundPost::Post {
                msg: BlockMessage::RbcInit(_) | BlockMessage::RbcChunk(_),
                ..
            } | BackgroundPost::Broadcast {
                msg: BlockMessage::RbcInit(_) | BlockMessage::RbcChunk(_),
                ..
            }
        )
    });
    assert!(
        !has_payload_posts,
        "RBC payload rebroadcasts should bypass the background queue"
    );
    let should_rebroadcast = harness
        .actor
        .should_rebroadcast_rbc_payload(&roster, high_key);
    let sent = &harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .payload_rebroadcast_last_sent;
    if should_rebroadcast {
        assert!(
            sent.contains_key(&high_key),
            "expected payload rebroadcast for highest pending block"
        );
        assert!(
            !sent.contains_key(&low_key),
            "expected payload rebroadcasts to target only the highest pending block"
        );
    } else {
        assert!(
            !sent.contains_key(&high_key) && !sent.contains_key(&low_key),
            "unexpected payload rebroadcast when local peer is not a rebroadcaster"
        );
    }

    harness.shutdown.send();
}

