#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_votes_lowest_view_first_for_same_height() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let _genesis_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let state_view = actor.state.view();
    let parent_hash = state_view.latest_block_hash();
    let height = u64::try_from(state_view.height())
        .unwrap_or(0)
        .saturating_add(1);
    drop(state_view);

    let mut candidates = Vec::new();
    for view in 0_u64..32 {
        let block = sample_block(height, view, parent_hash);
        let hash = block.hash();
        candidates.push((view, block, hash));
    }

    let mut selected = None;
    for i in 0..candidates.len() {
        for j in (i + 1)..candidates.len() {
            let (view_a, block_a, hash_a) = &candidates[i];
            let (view_b, block_b, hash_b) = &candidates[j];
            if view_a < view_b && hash_a > hash_b {
                selected = Some((block_a.clone(), block_b.clone()));
                break;
            }
            if view_b < view_a && hash_b > hash_a {
                selected = Some((block_b.clone(), block_a.clone()));
                break;
            }
        }
        if selected.is_some() {
            break;
        }
    }

    let (low_view_block, high_view_block) =
        selected.expect("failed to find view pair with inverse hash ordering");
    let low_view = low_view_block.header().view_change_index();
    let high_view = high_view_block.header().view_change_index();
    assert!(low_view < high_view);

    let low_payload = super::proposals::block_payload_bytes(&low_view_block);
    let low_payload_hash = Hash::new(&low_payload);
    let mut low_pending =
        PendingBlock::new(low_view_block.clone(), low_payload_hash, height, low_view);
    low_pending.validation_status = ValidationStatus::Valid;
    low_pending.parent_state_root = Some(zero_state_root());
    low_pending.post_state_root = Some(zero_state_root());
    actor
        .pending
        .pending_blocks
        .insert(low_view_block.hash(), low_pending);

    let high_payload = super::proposals::block_payload_bytes(&high_view_block);
    let high_payload_hash = Hash::new(&high_payload);
    let mut high_pending = PendingBlock::new(
        high_view_block.clone(),
        high_payload_hash,
        height,
        high_view,
    );
    high_pending.validation_status = ValidationStatus::Valid;
    high_pending.parent_state_root = Some(zero_state_root());
    high_pending.post_state_root = Some(zero_state_root());
    actor
        .pending
        .pending_blocks
        .insert(high_view_block.hash(), high_pending);

    actor.pending.last_commit_pipeline_run = Instant::now() - Duration::from_secs(10);
    actor.process_commit_candidates();

    let local_precommits: Vec<_> = actor
        .vote_log
        .values()
        .filter(|vote| vote.phase == Phase::Commit && vote.height == height)
        .collect();
    assert!(!local_precommits.is_empty());
    let lowest = local_precommits
        .iter()
        .min_by_key(|vote| vote.view)
        .expect("at least one precommit");
    assert_eq!(lowest.view, low_view);
    assert_eq!(lowest.block_hash, low_view_block.hash());

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_uses_commit_qc_roster_for_validation() {
    use crate::sumeragi::status;

    status::reset_commit_certs_for_tests();
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let active_roster = actor.effective_commit_topology();
    assert!(
        active_roster.len() >= 2,
        "test needs at least two validators to rotate roster"
    );
    let mut history_roster = active_roster.clone();
    history_roster.rotate_left(1);
    assert_ne!(
        history_roster, active_roster,
        "history roster should differ from active roster"
    );

    let parent_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x42; Hash::LENGTH]));
    {
        let mut hashes = actor.state.block_hashes.block();
        hashes.push(parent_hash);
        hashes.commit_for_tests();
    }

    let height = 2u64;
    let view = 0u64;
    let signature_topology = super::topology_for_view(
        &super::network_topology::Topology::new(history_roster.clone()),
        height,
        view,
        PERMISSIONED_TAG,
        None,
    );
    let signer_peer = signature_topology
        .as_ref()
        .first()
        .expect("commit topology not empty");
    let signer_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == signer_peer.public_key())
        .expect("signer keypair exists in harness");
    let header = BlockHeader {
        height: NonZeroU64::new(height).expect("block height must be non-zero"),
        prev_block_hash: Some(parent_hash),
        merkle_root: None,
        result_merkle_root: None,
        da_proof_policies_hash: None,
        da_commitments_hash: None,
        da_pin_intents_hash: None,
        creation_time_ms: 0,
        view_change_index: view,
        confidential_features: None,
    };
    let signature = SignatureOf::from_hash(signer_kp.private_key(), header.hash());
    let block_signature = BlockSignature::new(0, signature);
    let block = SignedBlock::presigned(block_signature, header, Vec::new());
    let block_hash = block.hash();

    let mut signers = BTreeSet::new();
    for idx in 0..history_roster.len() {
        signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, history_roster.len());
    let topology = super::network_topology::Topology::new(history_roster.clone());
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        height,
        view,
        0,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    let commit_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&history_roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: history_roster,
        aggregate: QcAggregate {
            signers_bitmap,
            bls_aggregate_signature,
        },
    };
    status::record_commit_qc(commit_qc);

    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let mut pending = PendingBlock::new(block, payload_hash, height, view);
    pending.validation_status = ValidationStatus::Valid;
    pending.parent_state_root = Some(zero_state_root());
    pending.post_state_root = Some(zero_state_root());
    actor.pending.pending_blocks.insert(block_hash, pending);
    actor.pending.last_commit_pipeline_run = Instant::now() - Duration::from_secs(10);

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Tick, None);

    let has_vote = actor.vote_log.values().any(|vote| {
        vote.phase == Phase::Commit
            && vote.block_hash == block_hash
            && vote.height == height
            && vote.view == view
    });
    assert!(
        has_vote,
        "commit pipeline should validate and emit precommit vote using commit certificate roster"
    );

    status::reset_commit_certs_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_rebuilds_qcs_with_empty_active_roster() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;

    let genesis_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let height = 2u64;
    let view = 0u64;
    let block = heartbeat_block_for_state(
        actor.state.as_ref(),
        &actor.common_config.chain,
        height,
        view,
        Some(genesis_hash),
        &actor.common_config.key_pair,
        0,
    );
    let block_hash = block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let mut pending = PendingBlock::new(block, payload_hash, height, view);
    pending.validation_status = ValidationStatus::Valid;
    pending.parent_state_root = Some(zero_state_root());
    pending.post_state_root = Some(zero_state_root());
    actor.pending.pending_blocks.insert(block_hash, pending);

    let roster = vec![actor.common_config.peer.id().clone()];
    let topology = super::network_topology::Topology::new(roster.clone());
    let signers_bitmap = vec![0b0000_0001];
    let chain = actor.common_config.chain.clone();
    let keypairs = vec![actor.common_config.key_pair.clone()];
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        height,
        view,
        0,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &chain,
        PERMISSIONED_TAG,
        block_hash,
        height,
        view,
        0,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let commit_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: roster.clone(),
        aggregate: QcAggregate {
            signers_bitmap: signers_bitmap.clone(),
            bls_aggregate_signature,
        },
    };
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        view,
        block_hash,
        commit_qc.parent_state_root,
        commit_qc.post_state_root,
        roster.clone(),
        signers_bitmap,
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );
    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut journal = state.commit_roster_journal.write();
        journal.upsert(commit_qc, checkpoint, None);
        state.commit_topology.mutate_vec(Vec::clear);
        state.prev_commit_topology.mutate_vec(Vec::clear);
        let mut block = state.world.block();
        block.peers.get_mut().clear();
        block.commit();
    }

    let mut vote = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch: 0,
        highest_qc: None,
        signer: 0,
        bls_sig: Vec::new(),
    };
    let preimage = super::vote_preimage(&chain, PERMISSIONED_TAG, &vote);
    let signature = Signature::new(actor.common_config.key_pair.private_key(), &preimage);
    vote.bls_sig = signature.payload().to_vec();
    assert!(
        !vote.bls_sig.is_empty(),
        "test vote should include a BLS signature"
    );
    actor
        .vote_log
        .insert((Phase::Commit, height, view, 0, 0), vote);

    assert!(
        actor
            .state
            .commit_roster_snapshot_for_block(height, block_hash)
            .is_some(),
        "commit roster snapshot should be available for QC rebuild"
    );
    let (consensus_mode, _, _) = actor.consensus_context_for_height(height);
    assert_eq!(
        consensus_mode,
        ConsensusMode::Permissioned,
        "test assumes permissioned consensus"
    );
    assert_eq!(
        actor.epoch_for_height(height),
        0,
        "permissioned consensus uses epoch 0"
    );
    let roster_cache =
        roster_cache_for_state(actor.state.as_ref(), actor.config.npos.epoch_length_blocks);
    let persisted = super::persisted_roster_for_block(
        actor.state.as_ref(),
        actor.kura.as_ref(),
        consensus_mode,
        height,
        block_hash,
        Some(view),
        &roster_cache,
        None,
    );
    assert!(
        persisted.is_some(),
        "persisted roster selection should validate in test setup"
    );
    let commit_roster = actor.roster_for_vote_with_mode(block_hash, height, view, consensus_mode);
    assert!(
        !commit_roster.is_empty(),
        "commit roster should be available for QC rebuild"
    );
    let topology = super::network_topology::Topology::new(commit_roster);
    let signers = actor.qc_signers_for_votes(Phase::Commit, block_hash, height, view, 0, &topology);
    assert!(
        !signers.is_empty(),
        "cached votes should validate against the commit roster"
    );
    let signature_topology =
        super::topology_for_view(&topology, height, view, PERMISSIONED_TAG, None);
    let canonical_signers =
        super::normalize_signer_indices_to_canonical(&signers, &signature_topology, &topology);
    assert!(
        !canonical_signers.is_empty(),
        "canonical signer mapping should not be empty"
    );
    let signers_bitmap = super::build_signers_bitmap(&canonical_signers, topology.as_ref().len());
    let aggregate_signature = super::aggregate_vote_signatures(
        &actor.vote_log,
        Phase::Commit,
        block_hash,
        height,
        view,
        0,
        &signers,
    )
    .expect("aggregate vote signatures");
    let validator_set = topology.as_ref().to_vec();
    let qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&validator_set),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set,
        aggregate: QcAggregate {
            signers_bitmap,
            bls_aggregate_signature: aggregate_signature,
        },
    };
    let world = world_with_consensus_keys(topology.as_ref(), &harness.key_pairs);
    let world_view = world.view();
    let inputs =
        roster_validation_inputs_for_view(&world_view, topology.as_ref(), consensus_mode, None);
    let (validation, _) = super::validate_qc_with_evidence(
        &actor.vote_log,
        &qc,
        &topology,
        &world_view,
        &inputs.pops,
        &actor.common_config.chain,
        consensus_mode,
        None,
        PERMISSIONED_TAG,
        None,
        None,
    );
    assert!(validation.is_ok(), "QC validation failed: {validation:?}");
    let pending_hashes: BTreeSet<_> = actor.pending.pending_blocks.keys().copied().collect();
    let candidates = super::stale_qc_candidates(
        actor.vote_log.values(),
        1,
        |hash| {
            pending_hashes.contains(&hash) || actor.kura.get_block_height_by_hash(hash).is_some()
        },
        |_| false,
    );
    assert!(!candidates.is_empty(), "expected QC rebuild candidates");
    assert!(
        actor.active_pending_blocks_len() > 0,
        "test requires an active pending block"
    );

    actor.pending.last_commit_pipeline_run = Instant::now() - Duration::from_secs(10);
    actor.last_qc_rebuild = Instant::now() - Duration::from_secs(10);
    let last_qc_rebuild = actor.last_qc_rebuild;

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Tick, None);

    assert!(
        actor.last_qc_rebuild > last_qc_rebuild,
        "commit pipeline should attempt QC rebuild"
    );
    assert!(
        actor
            .qc_cache
            .contains_key(&(Phase::Commit, block_hash, height, view, 0)),
        "QC rebuild should run even when the active commit roster is empty"
    );

    harness.shutdown.send();
}

