#[test]
fn select_new_view_highest_qc_accepts_prepare() {
    let highest_height = 1u64;
    let height = highest_height.saturating_add(1);
    let view = 0;
    let epoch = 0;
    let block = sample_block(highest_height, view, None);
    let block_hash = block.hash();
    let signer = ValidatorIndex::try_from(0).expect("signer index fits");
    let highest_prepare = QcHeaderRef {
        phase: Phase::Prepare,
        subject_block_hash: block_hash,
        height: highest_height,
        view,
        epoch,
    };
    let mut vote_log = BTreeMap::new();
    vote_log.insert(
        (Phase::NewView, height, view, epoch, signer),
        crate::sumeragi::consensus::Vote {
            phase: Phase::NewView,
            block_hash,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view,
            epoch,
            highest_qc: Some(highest_prepare),
            signer,
            bls_sig: Vec::new(),
        },
    );
    let mut signers = BTreeSet::new();
    signers.insert(signer);
    let selected =
        super::select_new_view_highest_qc_from_votes(&vote_log, &signers, height, view, epoch)
            .expect("highest QC should be selected");
    assert_eq!(selected.phase, Phase::Prepare);
    assert_eq!(selected.height, highest_height);
    assert_eq!(selected.view, view);
    assert_eq!(selected.subject_block_hash, block_hash);

    let commit_signer = ValidatorIndex::try_from(1).expect("signer index fits");
    let highest_commit = QcHeaderRef {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        height: highest_height,
        view,
        epoch,
    };
    vote_log.insert(
        (Phase::NewView, height, view, epoch, commit_signer),
        crate::sumeragi::consensus::Vote {
            phase: Phase::NewView,
            block_hash,
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view,
            epoch,
            highest_qc: Some(highest_commit),
            signer: commit_signer,
            bls_sig: Vec::new(),
        },
    );
    signers.insert(commit_signer);
    let selected =
        super::select_new_view_highest_qc_from_votes(&vote_log, &signers, height, view, epoch)
            .expect("highest QC should be selected");
    assert_eq!(selected.phase, Phase::Commit);
}

#[tokio::test(flavor = "current_thread")]
async fn try_form_qc_from_votes_skips_when_conflicts_locked_chain() {
    let _guard = super::status::qc_status_test_guard();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let locked_block = nonempty_block_for_actor(actor, &harness.key_pairs, 1, 0, None);
    let conflicting_block = nonempty_block_for_actor(actor, &harness.key_pairs, 2, 0, None);
    actor
        .kura
        .store_block(locked_block.clone())
        .expect("store locked block");
    actor
        .kura
        .store_block(conflicting_block.clone())
        .expect("store conflicting block");
    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    state.push_block_hash_for_testing(locked_block.hash());

    let epoch = actor.epoch_manager.as_ref().map_or(0, EpochManager::epoch);
    actor.locked_qc = Some(QcHeaderRef {
        phase: Phase::Commit,
        subject_block_hash: locked_block.hash(),
        height: 1,
        view: 0,
        epoch,
    });
    super::status::set_locked_qc(1, 0, Some(locked_block.hash()));

    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let chain = actor.common_config.chain.clone();
    let required = topology.min_votes_for_commit();
    let height = 2;
    let view = 0;

    for signer_idx in 0..required {
        let mut vote = crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash: conflicting_block.hash(),
            parent_state_root: zero_state_root(),
            post_state_root: zero_state_root(),
            height,
            view,
            epoch,
            highest_qc: None,
            signer: u32::try_from(signer_idx).expect("signer index fits u32"),
            bls_sig: Vec::new(),
        };
        sign_vote_for_view(&mut vote, &chain, &topology, &harness.key_pairs);
        actor.handle_vote(vote);
    }

    assert!(
        !actor.qc_cache.contains_key(&(
            Phase::Commit,
            conflicting_block.hash(),
            height,
            view,
            epoch
        )),
        "conflicting precommit QC should not be aggregated"
    );

    harness.shutdown.send();
}

