#[tokio::test(flavor = "current_thread")]
async fn handle_rbc_ready_runs_commit_pipeline_when_queue_backlogged() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    super::status::reset_worker_loop_snapshot_for_tests();

    let committed_height = actor.state.view().height() as u64;
    let height = committed_height.saturating_add(1).max(1);
    let key: SessionKey = (
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xE4; Hash::LENGTH])),
        height,
        0,
    );
    let epoch = actor.epoch_for_height(height);
    let payload = b"payload".to_vec();
    let payload_hash = Hash::new(&payload);
    let session = Actor::build_rbc_session_from_payload(&payload, payload_hash, 1024, epoch)
        .expect("session");
    let chunk_root = session.expected_chunk_root.expect("chunk root");
    actor.subsystems.da_rbc.rbc.sessions.insert(key, session);

    let roster = actor.effective_commit_topology();
    assert!(!roster.is_empty(), "test requires commit roster");
    actor.record_rbc_session_roster(key, roster.clone(), super::RbcRosterSource::Derived);

    let signer_peer = roster.first().expect("roster entry").public_key().clone();
    let signer_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == &signer_peer)
        .expect("signer keypair");
    let roster_hash = super::rbc::rbc_roster_hash(&roster);
    let mut ready = crate::sumeragi::consensus::RbcReady {
        block_hash: key.0,
        height: key.1,
        view: key.2,
        epoch,
        roster_hash,
        chunk_root,
        sender: 0,
        signature: Vec::new(),
    };
    let (_, mode_tag, _) = actor.consensus_context_for_height(height);
    let preimage = super::rbc_ready_preimage(&actor.chain_id, mode_tag, &ready);
    let signature = Signature::new(signer_kp.private_key(), &preimage);
    ready.signature = signature.payload().to_vec();
    let topology = super::network_topology::Topology::new(roster.clone());
    assert!(
        super::rbc::rbc_ready_signature_valid(&ready, &topology, &actor.chain_id, &mode_tag),
        "ready signature should validate against roster"
    );

    let pending_block = {
        let view = actor.state.view();
        sample_block(height, 0, view.latest_block_hash())
    };
    let pending_hash = pending_block.hash();
    let pending_payload_hash = Hash::new(super::proposals::block_payload_bytes(&pending_block));
    actor.pending.pending_blocks.insert(
        pending_hash,
        PendingBlock::new(pending_block, pending_payload_hash, height, 0),
    );
    {
        let pending = actor
            .pending
            .pending_blocks
            .get_mut(&pending_hash)
            .expect("pending block");
        pending.validation_status = ValidationStatus::Valid;
        pending.parent_state_root = Some(zero_state_root());
        pending.post_state_root = Some(zero_state_root());
    }
    assert!(
        actor.active_pending_blocks_len() > 0,
        "pending block should extend the committed tip"
    );

    let last_run = Instant::now() - Duration::from_secs(10);
    actor.pending.last_commit_pipeline_run = last_run;
    super::status::record_worker_queue_enqueue(super::status::WorkerQueueKind::Votes);
    let delivered_before = actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .is_some_and(|session| session.delivered);

    let ready_sender = ready.sender;
    actor.handle_rbc_ready(ready).expect("ready handled");

    let session_after = actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .expect("session retained");
    let ready_recorded = session_after
        .ready_signatures
        .iter()
        .any(|entry| entry.sender == ready_sender);
    let delivered_after = session_after.delivered;
    if ready_recorded && !delivered_before && !delivered_after {
        assert!(
            actor.pending.last_commit_pipeline_run > last_run,
            "commit pipeline should run when READY is recorded without DELIVER"
        );
    }

    super::status::record_worker_queue_drain(super::status::WorkerQueueKind::Votes, 1);
    super::status::reset_worker_loop_snapshot_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn handle_rbc_ready_drops_when_derived_roster_mismatches() {
    let mut harness = test_actor_harness(4).await;
    let key: SessionKey = (
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::new(b"rbc-ready-derived-mismatch")),
        6,
        0,
    );
    let epoch = harness.actor.epoch_for_height(key.1);
    let payload = b"payload".to_vec();
    let payload_hash = Hash::new(&payload);
    let mut session = Actor::build_rbc_session_from_payload(&payload, payload_hash, 1024, epoch)
        .expect("session");
    session.record_ready(0, vec![0xAA]);
    session.sent_ready = true;
    session.delivered = true;
    session.deliver_sender = Some(0);
    session.deliver_signature = Some(vec![0xBB]);

    harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key, session.clone());

    let roster = harness.actor.effective_commit_topology();
    assert!(!roster.is_empty());
    harness
        .actor
        .record_rbc_session_roster(key, roster.clone(), super::RbcRosterSource::Derived);

    let local_peer = harness.actor.common_config.peer.id().clone();
    let signer_peer = roster
        .iter()
        .find(|peer| *peer != &local_peer)
        .expect("signer peer")
        .clone();
    let signer_idx =
        signature_sender_index(&harness.actor, &roster, key.1, key.2, &signer_peer);
    let signer_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == signer_peer.public_key())
        .expect("signer keypair");
    let chunk_root = session.expected_chunk_root.expect("chunk root");

    let mut ready = crate::sumeragi::consensus::RbcReady {
        block_hash: key.0,
        height: key.1,
        view: key.2,
        epoch,
        roster_hash: Hash::prehashed([0xC3; Hash::LENGTH]),
        chunk_root,
        sender: u32::try_from(signer_idx).expect("signer index fits u32"),
        signature: Vec::new(),
    };
    let (_, mode_tag, _prf_seed) = harness.actor.consensus_context_for_height(key.1);
    let preimage = super::rbc_ready_preimage(&harness.actor.common_config.chain, mode_tag, &ready);
    let signature = Signature::new(signer_kp.private_key(), &preimage);
    ready.signature = signature.payload().to_vec();

    harness
        .actor
        .handle_rbc_ready(ready)
        .expect("ready handled");

    assert!(
        !harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .pending
            .contains_key(&key),
        "mismatched READY should be dropped with an authoritative roster"
    );
    assert!(
        harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .session_rosters
            .contains_key(&key),
        "derived roster should remain until an authoritative snapshot arrives"
    );
    assert!(
        harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .session_roster_sources
            .contains_key(&key),
        "roster source should remain until an authoritative snapshot arrives"
    );
    let stored = harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .expect("session");
    assert_eq!(stored.ready_signatures.len(), 1);
    assert!(stored.sent_ready);
    assert!(stored.delivered);
    assert!(stored.deliver_signature.is_some());
    assert!(stored.deliver_sender.is_some());

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn handle_rbc_ready_refreshes_roster_on_unverified_mismatch() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let committed_height = actor.state.view().height() as u64;
    let height = committed_height.saturating_add(1);
    let key: SessionKey = (
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::new(b"rbc-ready-derived-refresh")),
        height,
        0,
    );
    let epoch = actor.epoch_for_height(height);
    let payload = b"payload".to_vec();
    let payload_hash = Hash::new(&payload);
    let session = Actor::build_rbc_session_from_payload(&payload, payload_hash, 1024, epoch)
        .expect("session");
    let chunk_root = session.expected_chunk_root.expect("chunk root");
    actor.subsystems.da_rbc.rbc.sessions.insert(key, session);

    let roster_a = actor.effective_commit_topology();
    assert!(roster_a.len() > 1, "test requires multiple peers");
    actor.record_rbc_session_roster(key, roster_a.clone(), super::RbcRosterSource::Init);

    let mut roster_b = roster_a.clone();
    roster_b.pop();
    assert!(
        roster_b.len() > 1,
        "test requires at least two peers after roster change"
    );
    {
        let mut block = actor.state.commit_topology.block();
        {
            let mut tx = block.transaction();
            *tx = roster_b.clone();
            tx.apply();
        }
        block.commit();
    }

    let topology = super::network_topology::Topology::new(roster_b.clone());
    let (_, mode_tag, prf_seed) = actor.consensus_context_for_height(key.1);
    let signature_topology = super::topology_for_view(&topology, key.1, key.2, mode_tag, prf_seed);
    let local_peer = actor.common_config.peer.id().clone();
    let (sender_idx, signer_peer) = signature_topology
        .as_ref()
        .iter()
        .enumerate()
        .find(|(_, peer)| *peer != &local_peer)
        .map(|(idx, peer)| (idx, peer.clone()))
        .expect("signer peer");
    let signer_kp = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == signer_peer.public_key())
        .expect("signer keypair");

    let mut ready = crate::sumeragi::consensus::RbcReady {
        block_hash: key.0,
        height: key.1,
        view: key.2,
        epoch,
        roster_hash: roster_hash(&roster_b),
        chunk_root,
        sender: u32::try_from(sender_idx).expect("sender fits u32"),
        signature: Vec::new(),
    };
    let preimage = super::rbc_ready_preimage(&actor.common_config.chain, mode_tag, &ready);
    let signature = Signature::new(signer_kp.private_key(), &preimage);
    ready.signature = signature.payload().to_vec();

    actor.handle_rbc_ready(ready).expect("ready handled");

    assert_eq!(
        actor.subsystems.da_rbc.rbc.session_rosters.get(&key),
        Some(&roster_b)
    );
    assert_eq!(
        actor
            .subsystems
            .da_rbc
            .rbc
            .session_roster_sources
            .get(&key)
            .copied(),
        Some(super::RbcRosterSource::Derived)
    );
    let stored = actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .expect("session");
    let sender_idx = u32::try_from(sender_idx).expect("sender fits u32");
    assert!(
        stored
            .ready_signatures
            .iter()
            .any(|entry| entry.sender == sender_idx),
        "ready should be recorded after roster refresh"
    );
    assert!(
        !actor.subsystems.da_rbc.rbc.pending.contains_key(&key),
        "ready should not be stashed after roster refresh"
    );

    harness.shutdown.send();
}

