#[tokio::test(flavor = "current_thread")]
async fn rebroadcast_stalled_rbc_payloads_skips_when_queue_backpressured() {
    super::status::reset_worker_loop_snapshot_for_tests();
    let mut harness = test_actor_harness(4).await;
    harness.actor.queue_block_backpressure.reset_to_current();
    let key = insert_active_pending_block(&mut harness.actor, 0);
    let payload = vec![0xAB; 2048];
    let payload_hash = Hash::new(&payload);
    let mut session = Actor::build_rbc_session_from_payload(&payload, payload_hash, 1024, 0)
        .expect("rbc session");
    let pending_block = harness
        .actor
        .pending
        .pending_blocks
        .get(&key.0)
        .expect("pending block");
    session.test_set_block_header_and_signature(&pending_block.block);

    let roster = harness.actor.effective_commit_topology();
    assert!(!roster.is_empty());
    let topology = super::network_topology::Topology::new(roster.clone());
    let required = harness.actor.rbc_deliver_quorum(&topology);
    assert!(required > 0, "ready quorum should be non-zero");
    let (_, mode_tag, prf_seed) = harness.actor.consensus_context_for_height(key.1);
    let signature_topology = super::topology_for_view(&topology, key.1, key.2, mode_tag, prf_seed);
    let local_idx = harness
        .actor
        .local_validator_index_for_topology(&signature_topology)
        .expect("local sender");
    let available = signature_topology.as_ref().len().saturating_sub(1);
    assert!(
        required <= available,
        "test requires enough remote READY senders"
    );
    for (idx, _peer) in signature_topology.as_ref().iter().enumerate() {
        let idx = u32::try_from(idx).expect("sender fits u32");
        if idx == local_idx {
            continue;
        }
        session.record_ready(idx, vec![u8::try_from(idx).expect("index fits u8")]);
        if session.ready_signatures.len() >= required {
            break;
        }
    }
    assert!(session.ready_signatures.len() >= required);

    let missing_idx = session
        .chunks
        .iter()
        .position(Option::is_some)
        .expect("chunk present");
    session.chunks[missing_idx] = None;
    session.received_chunks = session.received_chunks.saturating_sub(1);
    session.sent_ready = true;

    harness
        .actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key, session);
    harness
        .actor
        .record_rbc_session_roster(key, roster, super::RbcRosterSource::Derived);

    super::status::record_worker_queue_blocked(
        super::status::WorkerQueueKind::RbcChunks,
        Duration::from_millis(5),
    );

    let _progress = harness
        .actor
        .rebroadcast_stalled_rbc_payloads(Instant::now());
    assert!(
        !harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .payload_rebroadcast_last_sent
            .contains_key(&key),
        "payload rebroadcast should remain idle while backpressured"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn rebroadcast_stalled_rbc_payloads_respects_session_budget() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.rbc.rebroadcast_sessions_per_tick = 1;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let local_peer_id = harness.actor.common_config.peer.id().clone();
    let mut roster = vec![local_peer_id.clone()];
    for peer in harness.actor.effective_commit_topology() {
        if peer != local_peer_id {
            roster.push(peer);
        }
    }
    assert!(roster.len() > 1, "test requires a multi-peer roster");

    let payload = vec![0xAB; 64];
    let payload_hash = Hash::new(&payload);
    for view in 0..=2_u64 {
        let key = insert_active_pending_block(&mut harness.actor, view);
        let mut session =
            Actor::build_rbc_session_from_payload(&payload, payload_hash, 32, 0).expect("session");
        let pending_block = harness
            .actor
            .pending
            .pending_blocks
            .get(&key.0)
            .expect("pending block");
        session.test_set_block_header_and_signature(&pending_block.block);
        harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .sessions
            .insert(key, session);
        harness.actor.record_rbc_session_roster(
            key,
            roster.clone(),
            super::RbcRosterSource::Derived,
        );
    }

    let progress = harness
        .actor
        .rebroadcast_stalled_rbc_payloads(Instant::now());
    assert!(progress);
    assert_eq!(
        harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .payload_rebroadcast_last_sent
            .len(),
        1
    );

    let _ = harness
        .actor
        .rebroadcast_stalled_rbc_payloads(Instant::now());
    assert_eq!(
        harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .payload_rebroadcast_last_sent
            .len(),
        2
    );

    let _ = harness
        .actor
        .rebroadcast_stalled_rbc_payloads(Instant::now());
    assert_eq!(
        harness
            .actor
            .subsystems
            .da_rbc
            .rbc
            .payload_rebroadcast_last_sent
            .len(),
        3
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn handle_rbc_ready_uses_activation_height_mode_tag() {
    use iroha_data_model::parameter::system::SumeragiConsensusMode;

    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let seed_epoch0 = [0xE1; 32];
    let seed_epoch1 = [0xE2; 32];
    seed_npos_epochs(actor, 1, seed_epoch0, seed_epoch1);

    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut block = state.world.block();
        let params = block.parameters.get_mut();
        params.sumeragi.next_mode = Some(SumeragiConsensusMode::Npos);
        params.sumeragi.mode_activation_height = Some(2);
        block.commit();
    }

    let _genesis_hash = seed_genesis_block_for_state(actor.state.as_ref());
    let height = 2u64;
    let view = 0u64;
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xE1; Hash::LENGTH]));
    let key = (block_hash, height, view);
    let payload = b"payload".to_vec();
    let payload_hash = Hash::new(&payload);
    let epoch = actor.epoch_for_height(height);
    let session = Actor::build_rbc_session_from_payload(&payload, payload_hash, 1024, epoch)
        .expect("session");

    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(key, session.clone());
    let roster = actor.effective_commit_topology();
    actor.record_rbc_session_roster(key, roster, super::RbcRosterSource::Derived);

    let ready = actor.build_rbc_ready(key, &session).expect("ready");
    let topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let prf_seed_value = {
        let view = actor.state.view();
        super::npos_seed_for_height(&view, height)
    };
    let signature_topology = super::topology_for_view(
        &topology,
        height,
        view,
        super::NPOS_TAG,
        Some(prf_seed_value),
    );

    assert!(
        super::rbc::rbc_ready_signature_valid(
            &ready,
            &signature_topology,
            &actor.common_config.chain,
            super::NPOS_TAG
        ),
        "ready signature should validate with activation height mode tag"
    );
    assert!(
        !super::rbc::rbc_ready_signature_valid(
            &ready,
            &signature_topology,
            &actor.common_config.chain,
            super::PERMISSIONED_TAG
        ),
        "ready signature should not validate with pre-activation mode tag"
    );

    actor.handle_rbc_ready(ready).expect("ready accepted");
    let stored = actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .expect("session");
    assert_eq!(stored.ready_signatures.len(), 1);

    harness.shutdown.send();
}

