#[tokio::test(flavor = "current_thread")]
async fn trim_block_sync_update_drops_commit_votes_to_fit() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let block = sample_block(1, 0, None);
    let mut update = super::message::BlockSyncUpdate::from(&block);
    let big_vote = crate::sumeragi::consensus::Vote {
        phase: Phase::Commit,
        block_hash: block.hash(),
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: block.header().height().get(),
        view: u64::from(block.header().view_change_index()),
        epoch: 0,
        highest_qc: None,
        signer: 0,
        bls_sig: vec![0u8; 4096],
    };
    update.commit_votes = vec![big_vote.clone(), big_vote];

    let mut no_votes = update.clone();
    no_votes.commit_votes.clear();
    actor.consensus_payload_frame_cap =
        super::block_sync_update_wire_len(actor.common_config.peer.id(), &no_votes);

    assert!(
        super::block_sync_update_wire_len(actor.common_config.peer.id(), &update)
            > actor.consensus_payload_frame_cap,
        "block sync update with commit votes should exceed the cap"
    );

    assert!(actor.trim_block_sync_update_for_frame_cap(&mut update));
    assert!(
        update.commit_votes.is_empty(),
        "commit votes should be trimmed"
    );
    assert!(
        super::block_sync_update_wire_len(actor.common_config.peer.id(), &update)
            <= actor.consensus_payload_frame_cap,
        "trimmed block sync update should fit"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn trim_block_sync_update_keeps_stake_snapshot_in_npos() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.da.enabled = true;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let roster = actor.effective_commit_topology();
    let stake_snapshot = crate::sumeragi::stake_snapshot::CommitStakeSnapshot::from_roster(
        actor.state.view().world(),
        &roster,
    )
    .expect("stake snapshot");
    let block = sample_block(1, 0, None);
    let mut update = super::message::BlockSyncUpdate::from(&block);
    update.stake_snapshot = Some(stake_snapshot);
    update.commit_qc = Some(Qc {
        phase: Phase::Commit,
        subject_block_hash: block.hash(),
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: block.header().height().get(),
        view: block.header().view_change_index(),
        epoch: 0,
        mode_tag: NPOS_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: roster.clone(),
        aggregate: QcAggregate {
            signers_bitmap: vec![0x01],
            bls_aggregate_signature: vec![0xAB; 96],
        },
    });
    update.validator_checkpoint = Some(ValidatorSetCheckpoint::new(
        block.header().height().get(),
        block.header().view_change_index(),
        block.hash(),
        zero_state_root(),
        zero_state_root(),
        roster.clone(),
        vec![0x01],
        vec![0xCD; 96],
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    ));

    let full_len = super::block_sync_update_wire_len(actor.common_config.peer.id(), &update);
    let mut no_commit_qc = update.clone();
    no_commit_qc.commit_qc = None;
    let trimmed_len =
        super::block_sync_update_wire_len(actor.common_config.peer.id(), &no_commit_qc);
    actor.consensus_payload_frame_cap = trimmed_len;

    assert!(
        full_len > actor.consensus_payload_frame_cap,
        "block sync update with commit QC should exceed payload cap"
    );
    assert!(actor.trim_block_sync_update_for_frame_cap(&mut update));
    assert!(update.commit_qc.is_none(), "commit QC should be trimmed");
    assert!(
        update.validator_checkpoint.is_some(),
        "checkpoint should be retained in NPoS"
    );
    assert!(
        update.stake_snapshot.is_some(),
        "stake snapshot should be retained in NPoS"
    );

    harness.shutdown.send();
}

#[test]
fn payload_rebroadcast_throttle_enforces_cooldown_per_block() {
    let mut throttle = super::PayloadRebroadcastThrottle::default();
    let hash_a = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xAA; 32]));
    let hash_b = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xBB; 32]));
    let now = Instant::now();
    let cooldown = Duration::from_millis(50);

    assert!(
        throttle.allow(hash_a, now, cooldown),
        "first send should be allowed"
    );
    assert!(
        !throttle.allow(hash_a, now + Duration::from_millis(10), cooldown),
        "cooldown should block repeated send for same block"
    );
    assert!(
        throttle.allow(hash_b, now, cooldown),
        "different block hash should be allowed during cooldown"
    );
    assert!(
        throttle.allow(hash_a, now + Duration::from_millis(60), cooldown),
        "cooldown expiry should allow resending the same block"
    );
}

#[test]
fn pending_block_stale_checks_committed_parent() {
    let committed = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xAA; 32]));
    let other_parent = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xBB; 32]));

    assert!(super::pending_block_stale_for_tip(
        5,
        Some(other_parent),
        4,
        Some(committed)
    ));
    assert!(super::pending_block_stale_for_tip(
        5,
        None,
        4,
        Some(committed)
    ));
    assert!(!super::pending_block_stale_for_tip(
        5,
        Some(committed),
        4,
        Some(committed)
    ));
    assert!(!super::pending_block_stale_for_tip(
        6,
        Some(other_parent),
        4,
        Some(committed)
    ));
}

