#[test]
fn block_sync_update_canonicalizes_signature_indices_for_roster() {
    let (peer_a, pop_a, _kp_a) = bls_peer("127.0.0.1:7095");
    let (peer_b, pop_b, kp_b) = bls_peer("127.0.0.1:7096");
    let (peer_c, pop_c, _kp_c) = bls_peer("127.0.0.1:7097");
    let mut pops = BTreeMap::new();
    pops.insert(peer_a.id().public_key().clone(), pop_a);
    pops.insert(peer_b.id().public_key().clone(), pop_b);
    pops.insert(peer_c.id().public_key().clone(), pop_c);
    let _trusted = trusted_with_pops(peer_a.clone(), vec![peer_b.clone(), peer_c.clone()], pops);

    let roster = vec![
        peer_a.id().clone(),
        peer_b.id().clone(),
        peer_c.id().clone(),
    ];
    let state = state_with_peers(roster.clone());
    {
        let mut block = state.commit_topology.block();
        let mut tx = block.transaction();
        *tx = roster.clone();
        tx.apply();
        block.commit();
    }
    let header = BlockHeader {
        height: NonZeroU64::new(2).expect("non-zero height"),
        prev_block_hash: None,
        merkle_root: None,
        result_merkle_root: None,
        da_proof_policies_hash: None,
        da_commitments_hash: None,
        da_pin_intents_hash: None,
        creation_time_ms: 0,
        view_change_index: 1,
        confidential_features: None,
    };
    let block_hash = header.hash();
    let signature = SignatureOf::from_hash(kp_b.private_key(), block_hash);
    let block_sig = BlockSignature::new(0, signature);
    let block = SignedBlock::presigned(block_sig, header, Vec::new());

    let signatures =
        super::canonicalize_block_signatures_for_roster(&block, &roster, PERMISSIONED_TAG, None);
    let expected_signers: BTreeSet<_> =
        [ValidatorIndex::try_from(1u32).expect("signer index fits")]
            .into_iter()
            .collect();
    let expected_bitmap = super::build_signers_bitmap(&expected_signers, roster.len());
    let checkpoint_signers: BTreeSet<_> = signatures
        .iter()
        .filter_map(|sig| ValidatorIndex::try_from(sig.index()).ok())
        .collect();
    let checkpoint_bitmap = super::build_signers_bitmap(&checkpoint_signers, roster.len());
    assert_eq!(checkpoint_bitmap, expected_bitmap);
}

#[test]
fn block_sync_update_uses_activation_height_mode_tag() {
    use iroha_data_model::parameter::system::SumeragiConsensusMode;

    let (peer_a, pop_a, kp_a) = bls_peer("127.0.0.1:7111");
    let (peer_b, pop_b, kp_b) = bls_peer("127.0.0.1:7112");
    let (peer_c, pop_c, kp_c) = bls_peer("127.0.0.1:7113");
    let mut pops = BTreeMap::new();
    pops.insert(peer_a.id().public_key().clone(), pop_a);
    pops.insert(peer_b.id().public_key().clone(), pop_b);
    pops.insert(peer_c.id().public_key().clone(), pop_c);
    let _trusted = trusted_with_pops(peer_a.clone(), vec![peer_b.clone(), peer_c.clone()], pops);
    let roster = vec![
        peer_a.id().clone(),
        peer_b.id().clone(),
        peer_c.id().clone(),
    ];
    let state = state_with_peers(roster.clone());
    {
        let mut block = state.world.block();
        let params = block.parameters.get_mut();
        params.sumeragi.next_mode = Some(SumeragiConsensusMode::Npos);
        params.sumeragi.mode_activation_height = Some(1);
        block.commit();
    }
    let height = 2u64;
    let seed = {
        let view = state.view();
        super::npos_seed_for_height(&view, height)
    };
    let roster_len = roster.len();
    let view = (0_u64..32)
        .find(|candidate| {
            let topo = super::network_topology::Topology::new(roster.clone());
            let npos_leader = topo.leader_index_prf(seed, height, *candidate);
            let candidate_usize = usize::try_from(*candidate).expect("candidate view fits usize");
            npos_leader != (candidate_usize % roster_len)
        })
        .expect("find view with differing rotations");
    let signature_topology =
        super::signature_topology_for_roster(&roster, height, view, NPOS_TAG, Some(seed));
    let signer_peer = signature_topology
        .as_ref()
        .first()
        .expect("signature topology not empty");
    let keypairs = [kp_a, kp_b, kp_c];
    let signer_kp = keypairs
        .iter()
        .find(|kp| kp.public_key() == signer_peer.public_key())
        .expect("signer keypair exists");
    let signer_index = roster
        .iter()
        .position(|peer| peer == signer_peer)
        .expect("signer exists in roster");
    let header = BlockHeader {
        height: NonZeroU64::new(height).expect("non-zero height"),
        prev_block_hash: None,
        merkle_root: None,
        result_merkle_root: None,
        da_proof_policies_hash: None,
        da_commitments_hash: None,
        da_pin_intents_hash: None,
        creation_time_ms: 0,
        view_change_index: view,
        confidential_features: None,
    };
    let signature = SignatureOf::from_hash(signer_kp.private_key(), header.hash());
    let block_signature = BlockSignature::new(0, signature);
    let block = SignedBlock::presigned(block_signature, header, Vec::new());

    let expected_signers: BTreeSet<_> =
        [ValidatorIndex::try_from(signer_index).expect("signer index fits")]
            .into_iter()
            .collect();
    let expected_bitmap = super::build_signers_bitmap(&expected_signers, roster.len());
    let signatures =
        super::canonicalize_block_signatures_for_roster(&block, &roster, NPOS_TAG, Some(seed));
    let checkpoint_signers: BTreeSet<_> = signatures
        .iter()
        .filter_map(|sig| ValidatorIndex::try_from(sig.index()).ok())
        .collect();
    let checkpoint_bitmap = super::build_signers_bitmap(&checkpoint_signers, roster.len());
    assert_eq!(checkpoint_bitmap, expected_bitmap);
}

#[test]
fn block_sync_update_uses_active_roster_for_checkpoint() {
    let (peer_a, pop_a, kp_a) = bls_peer("127.0.0.1:7101");
    let (peer_b, pop_b, _kp_b) = bls_peer("127.0.0.1:7102");
    let (peer_c, pop_c, _kp_c) = bls_peer("127.0.0.1:7103");
    let (peer_d, _pop_d, _kp_d) = bls_peer("127.0.0.1:7104");
    let mut pops = BTreeMap::new();
    pops.insert(peer_a.id().public_key().clone(), pop_a);
    pops.insert(peer_b.id().public_key().clone(), pop_b);
    pops.insert(peer_c.id().public_key().clone(), pop_c);
    let trusted = trusted_with_pops(
        peer_a.clone(),
        vec![peer_b.clone(), peer_c.clone(), peer_d.clone()],
        pops,
    );

    let state = state_with_peers(vec![
        peer_a.id().clone(),
        peer_b.id().clone(),
        peer_c.id().clone(),
        peer_d.id().clone(),
    ]);
    {
        let mut block = state.commit_topology.block();
        let mut tx = block.transaction();
        *tx = vec![
            peer_b.id().clone(),
            peer_c.id().clone(),
            peer_d.id().clone(),
            peer_a.id().clone(),
        ];
        tx.apply();
        block.commit();
    }
    let header = BlockHeader {
        height: NonZeroU64::new(9).expect("non-zero height"),
        prev_block_hash: None,
        merkle_root: None,
        result_merkle_root: None,
        da_proof_policies_hash: None,
        da_commitments_hash: None,
        da_pin_intents_hash: None,
        creation_time_ms: 0,
        view_change_index: 0,
        confidential_features: None,
    };
    let block_hash = header.hash();
    let block_sig = BlockSignature::new(0, SignatureOf::from_hash(kp_a.private_key(), block_hash));
    let block = SignedBlock::presigned(block_sig, header, Vec::new());

    let selection = select_block_sync_roster(
        &block,
        block.hash(),
        block.header().height().get(),
        None,
        None,
        None,
        &state,
        &trusted,
        peer_a.id(),
        PERMISSIONED_TAG,
        true,
    )
    .expect("roster selection");
    let view = state.view();
    let expected = derive_active_topology(&view, &trusted, peer_a.id());
    drop(view);
    assert_eq!(selection.roster, expected);
    assert_eq!(selection.roster.len(), 4);
}

#[test]
fn block_sync_update_uses_history_after_restart_like_path() {
    use crate::sumeragi::status;

    let _guard = status::commit_history_test_guard();
    status::reset_commit_certs_for_tests();
    status::reset_validator_checkpoints_for_tests();

    let (me_peer, me_pop, me_kp) = bls_peer("127.0.0.1:7086");
    let mut pops = BTreeMap::new();
    pops.insert(me_peer.id().public_key().clone(), me_pop);
    let trusted = trusted_with_pops(me_peer.clone(), Vec::new(), pops);
    let keypairs = vec![me_kp.clone()];
    let state = state_with_peers_and_keys(std::slice::from_ref(me_peer.id()), &keypairs);

    let height = 7;
    let header = BlockHeader {
        height: NonZeroU64::new(height).expect("non-zero height"),
        prev_block_hash: None,
        merkle_root: None,
        result_merkle_root: None,
        da_proof_policies_hash: None,
        da_commitments_hash: None,
        da_pin_intents_hash: None,
        creation_time_ms: 0,
        view_change_index: 0,
        confidential_features: None,
    };
    let block_hash = header.hash();
    let block_sig = BlockSignature::new(0, SignatureOf::from_hash(me_kp.private_key(), block_hash));
    let block = SignedBlock::presigned(block_sig.clone(), header, Vec::new());
    let roster = vec![me_peer.id().clone()];
    let mut signers = BTreeSet::new();
    signers.insert(ValidatorIndex::try_from(0).expect("signer index fits"));
    let signers_bitmap = super::build_signers_bitmap(&signers, roster.len());
    let topology = super::network_topology::Topology::new(roster.clone());
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &state.chain_id,
        PERMISSIONED_TAG,
        Phase::Commit,
        block_hash,
        height,
        0,
        0,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let checkpoint_signature = aggregate_vote_signature_for_bitmap(
        &state.chain_id,
        PERMISSIONED_TAG,
        block_hash,
        height,
        0,
        0,
        &signers_bitmap,
        &topology,
        &keypairs,
    );
    let commit_qc = Qc {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view: 0,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: roster.clone(),
        aggregate: QcAggregate {
            signers_bitmap: signers_bitmap.clone(),
            bls_aggregate_signature: bls_aggregate_signature.clone(),
        },
    };
    let checkpoint = ValidatorSetCheckpoint::new(
        height,
        commit_qc.view,
        block_hash,
        commit_qc.parent_state_root,
        commit_qc.post_state_root,
        roster,
        signers_bitmap,
        checkpoint_signature,
        VALIDATOR_SET_HASH_VERSION_V1,
        None,
    );

    // Simulate a prior sync run having populated the status history.
    status::record_commit_qc(commit_qc.clone());
    status::record_validator_checkpoint(checkpoint.clone());

    let kura = Kura::blank_kura_for_testing();
    let roster_cache = roster_cache_for_state(&state, EPOCH_LENGTH_BLOCKS);
    let update = block_sync_update_with_roster(
        &block,
        &state,
        &kura,
        ConsensusMode::Permissioned,
        &trusted,
        me_peer.id(),
        &roster_cache,
    );

    assert_eq!(
        update.commit_qc.as_ref(),
        Some(&commit_qc),
        "history commit certificate should be attached after restart-like path"
    );
    assert_eq!(
        update.validator_checkpoint.as_ref(),
        Some(&checkpoint),
        "history checkpoint should be attached after restart-like path"
    );

    let selection = select_block_sync_roster(
        &block,
        block_hash,
        block.header().height().get(),
        None,
        update.commit_qc.as_ref(),
        update.validator_checkpoint.as_ref(),
        &state,
        &trusted,
        me_peer.id(),
        super::PERMISSIONED_TAG,
        false,
    )
    .expect("roster selection");
    assert_eq!(
        selection.source,
        BlockSyncRosterSource::CommitCheckpointPairHint
    );

    status::reset_commit_certs_for_tests();
    status::reset_validator_checkpoints_for_tests();
}

#[test]
fn block_sync_roster_requires_certificate_or_checkpoint() {
    use crate::sumeragi::status;

    status::reset_commit_certs_for_tests();
    status::reset_validator_checkpoints_for_tests();
    let (me_peer, me_pop, me_kp) = bls_peer("127.0.0.1:7088");
    let (other_peer, other_pop, other_kp) = bls_peer("127.0.0.1:7089");
    let mut pops = BTreeMap::new();
    pops.insert(me_peer.id().public_key().clone(), me_pop);
    pops.insert(other_peer.id().public_key().clone(), other_pop);
    let trusted = trusted_with_pops(me_peer.clone(), vec![other_peer.clone()], pops);
    let roster = vec![me_peer.id().clone(), other_peer.id().clone()];
    let topology = super::network_topology::Topology::new(roster.clone());
    let mut valid_block =
        super::ValidBlock::new_dummy_and_modify_header(me_kp.private_key(), |header| {
            header.set_height(nonzero!(8_u64));
        });
    valid_block.sign(&other_kp, &topology);
    let block: SignedBlock = valid_block.into();
    let state = state_with_peers(Vec::new());

    let selection = select_block_sync_roster(
        &block,
        block.hash(),
        block.header().height().get(),
        None,
        None,
        None,
        &state,
        &trusted,
        me_peer.id(),
        super::PERMISSIONED_TAG,
        false,
    );
    assert!(
        selection.is_none(),
        "block sync roster selection must require certified roster artifacts"
    );
    status::reset_commit_certs_for_tests();
    status::reset_validator_checkpoints_for_tests();
}

