#[tokio::test(flavor = "current_thread")]
async fn apply_commit_outcome_updates_view_change_install() {
    use crate::block::ValidBlock;

    let mut harness = test_actor_harness(1).await;
    let _guard = super::status::view_change_proof_test_guard();
    super::status::reset_view_change_proof_counters_for_tests();
    super::status::set_view_change_index(0);
    let actor = &mut harness.actor;

    let leader_key = harness
        .key_pairs
        .first()
        .expect("leader keypair available")
        .private_key();
    let valid_block = ValidBlock::new_dummy_and_modify_header(leader_key, |header| {
        header.set_height(nonzero!(1_u64));
        header.set_view_change_index(1);
    });
    let committed_block = valid_block.clone().commit_unchecked().unpack(|_| {});
    let signed_block: SignedBlock = valid_block.into();
    let block_hash = signed_block.hash();
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&signed_block));
    let pending = PendingBlock::new(signed_block, payload_hash, 1, 1);
    let lock = QcHeaderRef {
        phase: Phase::Commit,
        subject_block_hash: block_hash,
        height: 1,
        view: 1,
        epoch: 0,
    };
    let commit_topology = actor.effective_commit_topology();
    let signature_topology = commit_topology.clone();
    let inflight = CommitInFlight {
        id: 1,
        lock,
        block_hash,
        pending,
        commit_topology,
        signature_topology,
        qc_signers: None,
        commit_qc: None,
        allow_quorum_bypass: false,
        post_commit_qc: None,
        enqueue_time: Instant::now(),
    };

    actor.subsystems.commit.inflight = Some(inflight);
    let (result_tx, result_rx) = mpsc::sync_channel(1);
    actor.subsystems.commit.result_rx = Some(result_rx);
    let now = Instant::now();
    let stale_hash = HashOf::from_untyped_unchecked(Hash::prehashed([0xA5; Hash::LENGTH]));
    let future_hash = HashOf::from_untyped_unchecked(Hash::prehashed([0xB4; Hash::LENGTH]));
    actor.pending.missing_block_requests.insert(
        stale_hash,
        MissingBlockRequest {
            height: 1,
            view: 0,
            phase: Phase::Commit,
            priority: MissingBlockPriority::Consensus,
            retry_window: Duration::from_secs(1),
            view_change_window: Some(Duration::from_secs(1)),
            first_seen: now,
            last_requested: now,
            view_change_triggered_view: None,
            attempts: 0,
        },
    );
    actor.pending.missing_block_requests.insert(
        future_hash,
        MissingBlockRequest {
            height: 2,
            view: 0,
            phase: Phase::Commit,
            priority: MissingBlockPriority::Consensus,
            retry_window: Duration::from_secs(1),
            view_change_window: Some(Duration::from_secs(1)),
            first_seen: now,
            last_requested: now,
            view_change_triggered_view: None,
            attempts: 0,
        },
    );
    result_tx
        .send(commit::CommitResult {
            id: 1,
            outcome: commit::CommitOutcome::Success {
                committed_block,
                exec_witness: None,
                pipeline_events: Vec::new(),
                state_events: Vec::new(),
            },
            timings: commit::CommitStageTimings::default(),
        })
        .expect("send commit result");
    assert!(
        actor.poll_commit_results(),
        "commit outcome should be applied"
    );
    assert!(
        !actor
            .pending
            .missing_block_requests
            .contains_key(&stale_hash),
        "stale missing block requests should be cleared after commit"
    );
    assert!(
        actor
            .pending
            .missing_block_requests
            .contains_key(&future_hash),
        "future missing block requests should be retained after commit"
    );

    let snapshot = super::status::snapshot();
    assert_eq!(snapshot.view_change_index, 1);
    assert_eq!(snapshot.view_change_install_total, 1);

    harness.shutdown.send();
}

#[test]
fn pacemaker_defers_under_backpressure() {
    let start = Instant::now();
    let mut pacemaker = Pacemaker::with_interval(Duration::from_millis(10), start);
    let mut tracker = PacemakerBackpressure::new();
    let state = BackpressureState::Saturated {
        queued: 5,
        capacity: NonZeroUsize::new(5).expect("non-zero"),
    };
    let backpressure = ProposalBackpressure {
        queue_state: state,
        active_pending: false,
        rbc_backlog: false,
        relay_backpressure: false,
        consensus_queue_backpressure: false,
    };
    let (log_initial, log_fire, should_attempt) =
        Actor::evaluate_pacemaker(&mut pacemaker, &mut tracker, backpressure, start);
    assert!(log_initial);
    assert!(log_fire);
    assert!(!should_attempt);
}

#[test]
