fn stale_qc_candidates_detects_missing_qc() {
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x91; Hash::LENGTH]));
    let votes = [
        crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash,
            parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            height: 4,
            view: 2,
            epoch: 1,
            highest_qc: None,
            signer: 0,
            bls_sig: Vec::new(),
        },
        crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash,
            parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            height: 4,
            view: 2,
            epoch: 1,
            highest_qc: None,
            signer: 1,
            bls_sig: Vec::new(),
        },
        crate::sumeragi::consensus::Vote {
            phase: Phase::Commit,
            block_hash,
            parent_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            post_state_root: iroha_crypto::Hash::prehashed([0u8; iroha_crypto::Hash::LENGTH]),
            height: 4,
            view: 2,
            epoch: 1,
            highest_qc: None,
            signer: 1,
            bls_sig: Vec::new(),
        },
    ];

    let candidates =
        super::stale_qc_candidates(votes.iter(), 2, |hash| hash == block_hash, |_| false);

    assert_eq!(candidates.len(), 1);
    let (key, count) = &candidates[0];
    assert_eq!(*count, 2);
    assert_eq!(*key, (Phase::Commit, block_hash, 4, 2, 1));
}

