#[tokio::test(flavor = "current_thread")]
async fn vote_roster_empty_for_gap_without_history() {
    use crate::sumeragi::status;

    status::reset_commit_certs_for_tests();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let hash_height1 =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x71; Hash::LENGTH]));
    let hash_height2 =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x72; Hash::LENGTH]));
    {
        let mut hashes = actor.state.block_hashes.block();
        hashes.push(hash_height1);
        hashes.push(hash_height2);
        hashes.commit_for_tests();
    }

    let gap_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x74; Hash::LENGTH]));
    let derived = actor.roster_for_vote_with_mode(gap_hash, 4, 0, ConsensusMode::Permissioned);
    assert!(
        derived.is_empty(),
        "vote roster should be empty when history is missing for a gap height"
    );

    status::reset_commit_certs_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn vote_roster_empty_when_parent_hash_known_but_history_mismatched() {
    use crate::sumeragi::status;

    status::reset_commit_certs_for_tests();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let block1 = nonempty_block_for_actor(actor, &harness.key_pairs, 1, 0, None);
    let block2 = nonempty_block_for_actor(actor, &harness.key_pairs, 2, 0, Some(block1.hash()));
    let block3 = sample_block(3, 0, Some(block2.hash()));
    actor
        .kura
        .store_block(block1.clone())
        .expect("store block 1");
    actor
        .kura
        .store_block(block2.clone())
        .expect("store block 2");
    actor
        .kura
        .store_block(block3.clone())
        .expect("store block 3");
    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    state.push_block_hash_for_testing(block1.hash());
    state.push_block_hash_for_testing(block2.hash());
    state.push_block_hash_for_testing(block3.hash());

    let block4 = sample_block(4, 0, Some(block3.hash()));
    let block5 = sample_block(5, 0, Some(block4.hash()));
    let block6 = sample_block(6, 0, Some(block5.hash()));
    for block in [block4.clone(), block5.clone(), block6.clone()] {
        let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
        let height = block.header().height().get();
        let block_hash = block.hash();
        actor.pending.pending_blocks.insert(
            block_hash,
            PendingBlock::new(block, payload_hash, height, 0),
        );
    }

    let roster = actor.effective_commit_topology();
    let mut signers = BTreeSet::new();
    for idx in 0..roster.len() {
        signers.insert(ValidatorIndex::try_from(idx).expect("signer index fits"));
    }
    let signers_bitmap = super::build_signers_bitmap(&signers, roster.len());
    let topology = super::network_topology::Topology::new(roster.clone());
    let hash_height5_alt =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x5A; Hash::LENGTH]));
    let bls_aggregate_signature = aggregate_signature_for_bitmap(
        &actor.common_config.chain,
        PERMISSIONED_TAG,
        Phase::Commit,
        hash_height5_alt,
        5,
        0,
        0,
        &signers_bitmap,
        &topology,
        &harness.key_pairs,
    );
    status::record_commit_qc(Qc {
        phase: Phase::Commit,
        subject_block_hash: hash_height5_alt,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height: 5,
        view: 0,
        epoch: 0,
        mode_tag: PERMISSIONED_TAG.to_string(),
        highest_qc: None,
        validator_set_hash: HashOf::new(&roster),
        validator_set_hash_version: VALIDATOR_SET_HASH_VERSION_V1,
        validator_set: roster,
        aggregate: QcAggregate {
            signers_bitmap,
            bls_aggregate_signature,
        },
    });

    let derived = actor.roster_for_vote_with_mode(block6.hash(), 6, 0, ConsensusMode::Permissioned);
    assert!(
        derived.is_empty(),
        "vote roster should be empty when commit-QC history mismatches the known parent hash"
    );

    status::reset_commit_certs_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn ensure_rbc_session_roster_falls_back_to_prev_commit_topology_without_snapshot() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let height = 2u64;
    let view = 0u64;
    let block_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xD2; Hash::LENGTH]));
    let key: SessionKey = (block_hash, height, view);

    let roster = actor.effective_commit_topology();
    let local_peer_id = actor.common_config.peer.id();
    let removed_peer = roster
        .iter()
        .find(|peer| *peer != local_peer_id)
        .cloned()
        .expect("non-local roster entry");

    let mut roster_new = roster.clone();
    roster_new.retain(|peer| peer != &removed_peer);
    assert!(!roster_new.is_empty(), "roster should remain non-empty");
    {
        let mut prev_block = actor.state.prev_commit_topology.block();
        prev_block.mutate_vec(|vec| *vec = roster.clone());
        prev_block.commit();
    }
    {
        let mut topo_block = actor.state.commit_topology.block();
        topo_block.mutate_vec(|vec| *vec = roster_new);
        topo_block.commit();
    }
    {
        let mut hashes = actor.state.block_hashes.block();
        hashes.push(HashOf::from_untyped_unchecked(Hash::prehashed(
            [0xD1; Hash::LENGTH],
        )));
        hashes.push(block_hash);
        hashes.commit_for_tests();
    }

    let rbc_roster = actor.ensure_rbc_session_roster(key);
    assert_eq!(
        rbc_roster, roster,
        "committed height should fall back to the previous commit topology"
    );
    assert_eq!(
        actor.rbc_session_roster(key),
        roster,
        "ensure should cache the derived roster for the session"
    );
    assert_eq!(
        actor.rbc_session_roster_source(key),
        Some(super::RbcRosterSource::Derived),
        "derived roster should remain non-authoritative until init arrives"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn handle_evidence_uses_subject_height_prf_seed() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Npos;
    consensus_cfg.da.enabled = true;
    consensus_cfg.npos.epoch_length_blocks = 1;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let seed_epoch0 = [0x33; 32];
    let seed_epoch1 = [0x44; 32];
    seed_npos_epochs(actor, 1, seed_epoch0, seed_epoch1);

    let topology_peers = actor.effective_commit_topology();
    let topology = super::network_topology::Topology::new(topology_peers.clone());
    let height = 1u64;
    let view = 0u64;
    let epoch = actor.epoch_for_height(height);
    let rotated =
        super::topology_for_view(&topology, height, view, super::NPOS_TAG, Some(seed_epoch0));
    let signer_idx = 0usize;
    let signer = u32::try_from(signer_idx).expect("signer index fits u32");
    let peer = rotated
        .as_ref()
        .get(signer_idx)
        .expect("signer present in topology");
    let keypair = harness
        .key_pairs
        .iter()
        .find(|kp| kp.public_key() == peer.public_key())
        .expect("matching keypair for signer");

    let block_hash_a =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xB1; Hash::LENGTH]));
    let block_hash_b =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xB2; Hash::LENGTH]));
    let mut vote_a = crate::sumeragi::consensus::Vote {
        phase: Phase::Prepare,
        block_hash: block_hash_a,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: None,
        signer,
        bls_sig: Vec::new(),
    };
    let mut vote_b = crate::sumeragi::consensus::Vote {
        phase: Phase::Prepare,
        block_hash: block_hash_b,
        parent_state_root: zero_state_root(),
        post_state_root: zero_state_root(),
        height,
        view,
        epoch,
        highest_qc: None,
        signer,
        bls_sig: Vec::new(),
    };

    for vote in [&mut vote_a, &mut vote_b] {
        let preimage = super::vote_preimage(&actor.common_config.chain, super::NPOS_TAG, vote);
        let sig = Signature::new(keypair.private_key(), &preimage);
        vote.bls_sig = sig.payload().to_vec();
    }

    let evidence =
        crate::sumeragi::evidence::check_double_vote(&vote_a, &vote_b).expect("double vote");
    actor
        .handle_evidence(evidence.clone())
        .expect("handle_evidence");

    let key = crate::sumeragi::evidence::evidence_key(&evidence);
    let view = actor.state.world.consensus_evidence.view();
    assert!(view.get(&key).is_some(), "evidence should be recorded");
    harness.shutdown.send();
}

