#[tokio::test(flavor = "current_thread")]
async fn assemble_proposal_skips_view_overflow() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let height = 1u64;
    let view = u64::MAX;
    let highest_qc = sample_qc_ref(0, 0);
    let mut topology = super::network_topology::Topology::new(actor.effective_commit_topology());

    let assembled = actor
        .assemble_and_broadcast_proposal(
            height,
            view,
            highest_qc,
            &mut topology,
            /*leader_index*/ 0,
            /*local_validator_index*/ 0,
            Instant::now(),
        )
        .expect("proposal assembly should skip overflow view");
    assert!(!assembled, "overflow view should not assemble a proposal");

    assert!(
        actor.pending.pending_blocks.is_empty(),
        "overflow view should not enqueue pending blocks"
    );
    assert!(
        actor.subsystems.propose.proposals_seen.is_empty(),
        "overflow view should not mark proposals as seen"
    );
    assert!(
        actor
            .subsystems
            .propose
            .proposal_cache
            .get_hint(height, view)
            .is_none(),
        "overflow view should not cache proposal hints"
    );
    assert!(
        actor
            .subsystems
            .propose
            .proposal_cache
            .get_proposal(height, view)
            .is_none(),
        "overflow view should not cache proposals"
    );
    assert!(
        actor.phase_tracker.current_view(height).is_none(),
        "phase tracker should not advance on overflow view"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn assemble_proposal_schedules_rbc_after_proposal_messages() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    consensus_cfg.rbc.chunk_max_bytes = 1024;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    let background_log: Arc<Mutex<Vec<super::BackgroundRequestLogEntry>>> =
        Arc::new(Mutex::new(Vec::new()));
    actor.background_request_log = Some(Arc::clone(&background_log));

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let height = 1u64;
    let highest_qc = sample_qc_ref(0, 0);
    let mut topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let (_, _, prf_seed) = actor.consensus_context_for_height(height);
    let seed = prf_seed.expect("PRF seed available");
    topology.canonicalize_order();
    topology.shuffle_prf(seed, height);
    let local_pos = topology
        .position(actor.common_config.peer.id().public_key())
        .expect("local peer in topology");
    let view = u64::try_from(local_pos).expect("view fits u64");
    let leader_index = actor
        .leader_index_for(&mut topology, height, view)
        .expect("leader index");
    let local_idx = actor
        .local_validator_index_for_topology(&topology)
        .expect("local validator index");
    let leader_index_u32 = u32::try_from(leader_index).expect("leader index fits u32");
    assert_eq!(
        leader_index_u32, local_idx,
        "local peer must be leader for proposal assembly"
    );

    let assembled = actor
        .assemble_and_broadcast_proposal(
            height,
            view,
            highest_qc,
            &mut topology,
            /*leader_index*/ leader_index,
            /*local_validator_index*/ local_idx,
            Instant::now(),
        )
        .expect("proposal assembly should succeed");
    assert!(assembled, "proposal assembly should succeed");

    let posts = background_log
        .lock()
        .expect("background request log mutex poisoned")
        .clone();
    let mut proposal_indexes = Vec::new();
    let mut rbc_indexes = Vec::new();
    for (idx, post) in posts.iter().enumerate() {
        match post.msg_kind {
            Some("Proposal") | Some("BlockCreated") => proposal_indexes.push(idx),
            Some("RbcInit") | Some("RbcChunk") | Some("RbcReady") => rbc_indexes.push(idx),
            _ => (),
        }
    }
    assert!(
        !proposal_indexes.is_empty(),
        "proposal messages should be scheduled"
    );
    assert!(!rbc_indexes.is_empty(), "RBC messages should be scheduled");
    let last_proposal = *proposal_indexes.iter().max().expect("proposal index");
    let first_rbc = *rbc_indexes.iter().min().expect("RBC index");
    assert!(
        first_rbc > last_proposal,
        "RBC messages should be scheduled after proposal messages"
    );

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn assemble_proposal_defers_when_highest_qc_block_missing() {
    use std::borrow::Cow;

    let _guard = super::status::qc_status_test_guard();
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let locked_block = nonempty_block_for_actor(actor, &harness.key_pairs, 1, 0, None);
    let locked_hash = locked_block.hash();
    actor
        .kura
        .store_block(locked_block)
        .expect("store locked block");
    let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
    state.push_block_hash_for_testing(locked_hash);

    let epoch = actor.epoch_for_height(1);
    actor.locked_qc = Some(QcHeaderRef {
        height: 1,
        view: 0,
        epoch,
        subject_block_hash: locked_hash,
        phase: Phase::Commit,
    });
    super::status::set_locked_qc(1, 0, Some(locked_hash));

    let tx = sample_transaction();
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");

    let height = 2u64;
    let view = 0u64;
    let missing_hash =
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x55; Hash::LENGTH]));
    let highest_qc = QcHeaderRef {
        height: 1,
        view: 0,
        epoch,
        subject_block_hash: missing_hash,
        phase: Phase::Commit,
    };
    let mut topology = super::network_topology::Topology::new(actor.effective_commit_topology());
    let local_idx = actor
        .local_validator_index(&actor.state.view())
        .expect("local validator index");

    let _ = harness.background_rx.try_iter().count();
    let assembled = actor
        .assemble_and_broadcast_proposal(
            height,
            view,
            highest_qc,
            &mut topology,
            /*leader_index*/ 0,
            /*local_validator_index*/ local_idx,
            Instant::now(),
        )
        .expect("proposal assembly should succeed");
    assert!(
        !assembled,
        "proposal assembly should defer when highest QC block is missing locally"
    );
    let request = actor
        .pending
        .missing_block_requests
        .get(&missing_hash)
        .expect("missing-block fetch should be scheduled for the highest QC block");
    assert_eq!(request.height, highest_qc.height);
    assert_eq!(request.view, highest_qc.view);
    assert_eq!(request.phase, Phase::Commit);
    assert_eq!(request.priority, super::MissingBlockPriority::Consensus);
    let posts: Vec<_> = harness.background_rx.try_iter().collect();
    assert!(
        !posts.iter().any(|post| matches!(
            post,
            BackgroundPost::Post {
                msg: BlockMessage::Proposal(_) | BlockMessage::BlockCreated(_),
                ..
            }
        )),
        "proposal messages should not be enqueued while waiting on missing block"
    );

    super::status::set_locked_qc(0, 0, None);
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn proposal_queue_scan_budget_limits_fetch() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    for _ in 0..5 {
        let tx = sample_transaction();
        actor
            .queue
            .push(
                AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
                actor.state.view(),
            )
            .expect("push tx");
    }

    let state_view = actor.state.view();
    let mut tx_guards = Vec::new();
    let deferred = actor.pull_transactions_for_proposal(
        &state_view,
        nonzero!(5_usize),
        2,
        None,
        &mut tx_guards,
        1,
        0,
    );

    assert!(deferred.is_empty(), "budgeted scan should not defer txs");
    assert_eq!(tx_guards.len(), 2, "scan budget should cap selection");

    drop(state_view);
    drop(tx_guards);

    assert_eq!(actor.queue.queued_len(), 3, "remaining txs stay queued");

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn proposal_filter_drops_committed_transactions_after_queue_scan() {
    let mut harness = test_actor_harness(4).await;
    let actor = &mut harness.actor;

    let committed_tx = sample_transaction();
    let live_tx = sample_transaction();

    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(committed_tx.clone())),
            actor.state.view(),
        )
        .expect("push committed tx");
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(live_tx.clone())),
            actor.state.view(),
        )
        .expect("push live tx");

    let height = 1u64;
    let view = 0u64;
    let state_view = actor.state.view();
    let mut tx_guards = Vec::new();
    let _ = actor.pull_transactions_for_proposal(
        &state_view,
        nonzero!(2_usize),
        2,
        None,
        &mut tx_guards,
        height,
        view,
    );
    drop(state_view);

    assert_eq!(tx_guards.len(), 2, "queue should return both transactions");

    let transactions: Vec<_> = tx_guards
        .iter()
        .map(crate::queue::TransactionGuard::clone_accepted)
        .collect();
    let routing: Vec<_> = tx_guards
        .iter()
        .map(crate::queue::TransactionGuard::routing)
        .collect();

    {
        let state = Arc::get_mut(&mut actor.state).expect("state uniquely held");
        let mut tx_block = state.transactions.block();
        let next_height = state
            .transactions_latest_height_for_testing()
            .saturating_add(1);
        let next_height =
            NonZeroUsize::new(next_height).expect("transaction height must be non-zero");
        tx_block.insert_block_with_single_tx(committed_tx.hash(), next_height);
        tx_block.commit().expect("commit transactions block");
    }

    let (filtered_guards, filtered_transactions, _filtered_routing, dropped) =
        Actor::filter_committed_transactions_for_proposal(
            &actor.state,
            tx_guards,
            transactions,
            routing,
            height,
            view,
        );

    assert_eq!(dropped, 1, "one committed transaction should be dropped");
    assert_eq!(
        filtered_transactions.len(),
        1,
        "only the live transaction should remain"
    );
    assert_eq!(
        filtered_transactions[0].hash(),
        live_tx.hash(),
        "live transaction should remain in proposal batch"
    );

    drop(filtered_guards);

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn proposal_gas_budget_limits_fetch() {
    use iroha_data_model::transaction::Executable;

    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;

    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;

    let tx = sample_transaction();
    let instructions = match tx.instructions() {
        Executable::Instructions(batch) => batch.iter().map(Clone::clone).collect::<Vec<_>>(),
        Executable::Ivm(_) => panic!("sample transaction should be ISI-based"),
    };
    let gas_cost = crate::gas::meter_instructions(&instructions);
    assert!(gas_cost > 0, "expected non-zero ISI gas cost");
    let gas_cap = NonZeroU64::new(gas_cost).expect("non-zero gas cap");

    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(tx)),
            actor.state.view(),
        )
        .expect("push tx");
    actor
        .queue
        .push(
            AcceptedTransaction::new_unchecked(Cow::Owned(sample_transaction())),
            actor.state.view(),
        )
        .expect("push tx");

    let state_view = actor.state.view();
    let mut tx_guards = Vec::new();
    let deferred = actor.pull_transactions_for_proposal(
        &state_view,
        nonzero!(5_usize),
        5,
        Some(gas_cap),
        &mut tx_guards,
        1,
        0,
    );

    assert_eq!(tx_guards.len(), 1, "gas cap should allow one tx");
    assert_eq!(deferred.len(), 1, "second tx should be deferred");

    drop(state_view);
    drop(tx_guards);

    for tx in deferred {
        actor
            .queue
            .push(tx, actor.state.view())
            .expect("requeue deferred tx");
    }

    assert_eq!(
        actor.queue.queued_len(),
        1,
        "deferred tx should remain queued"
    );

    harness.shutdown.send();
}

