#[test]
fn signer_index_normalization_round_trips_across_view_rotation() {
    let kp_a = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_b = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_c = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let topology = super::network_topology::Topology::new(vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
        PeerId::new(kp_c.public_key().clone()),
    ]);
    let canonical_roster = super::roster::canonicalize_roster(topology.as_ref().to_vec());
    let canonical_topology = super::network_topology::Topology::new(canonical_roster);
    let signature_topology =
        super::topology_for_view(&canonical_topology, 1, 1, super::PERMISSIONED_TAG, None);

    let canonical_signers: BTreeSet<ValidatorIndex> = [0_u32, 2_u32]
        .into_iter()
        .map(|idx| ValidatorIndex::try_from(idx).expect("validator index parses"))
        .collect();
    let view_signers = super::normalize_signer_indices_to_view(
        &canonical_signers,
        &signature_topology,
        &canonical_topology,
    );
    assert_eq!(view_signers.len(), canonical_signers.len());

    let roundtrip = super::normalize_signer_indices_to_canonical(
        &view_signers,
        &signature_topology,
        &canonical_topology,
    );
    assert_eq!(roundtrip, canonical_signers);

    for signer in &canonical_signers {
        let view_idx = super::view_index_for_canonical_signer(
            *signer,
            &signature_topology,
            &canonical_topology,
        )
        .expect("canonical signer should map to view index");
        assert!(view_signers.contains(&view_idx));
    }
}

#[test]
fn view_index_for_canonical_signer_accounts_for_rotation_offset() {
    let kp_a = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_b = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_c = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let topology = super::network_topology::Topology::new(vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
        PeerId::new(kp_c.public_key().clone()),
    ]);
    let canonical_roster = super::roster::canonicalize_roster(topology.as_ref().to_vec());
    let canonical_topology = super::network_topology::Topology::new(canonical_roster);
    let mut rotated = canonical_topology.clone();
    rotated.nth_rotation(1);

    let canonical0 = ValidatorIndex::try_from(0_u32).expect("validator index parses");
    let canonical1 = ValidatorIndex::try_from(1_u32).expect("validator index parses");
    let canonical2 = ValidatorIndex::try_from(2_u32).expect("validator index parses");

    let view0 = super::view_index_for_canonical_signer(canonical0, &rotated, &canonical_topology)
        .expect("maps");
    let view1 = super::view_index_for_canonical_signer(canonical1, &rotated, &canonical_topology)
        .expect("maps");
    let view2 = super::view_index_for_canonical_signer(canonical2, &rotated, &canonical_topology)
        .expect("maps");

    assert_eq!(
        view0,
        ValidatorIndex::try_from(2_u32).expect("validator index parses")
    );
    assert_eq!(
        view1,
        ValidatorIndex::try_from(0_u32).expect("validator index parses")
    );
    assert_eq!(
        view2,
        ValidatorIndex::try_from(1_u32).expect("validator index parses")
    );
}

#[test]
fn topology_for_view_rotates_npos_prf_leader() {
    let kp_a = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_b = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let kp_c = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let topology = super::network_topology::Topology::new(vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
        PeerId::new(kp_c.public_key().clone()),
    ]);

    let seed = [0x22_u8; 32];
    let mut height = 1u64;
    let mut view = 0u64;
    let mut leader = topology.leader_index_prf(seed, height, view);
    if leader == 0 {
        'search: for h in 1u64..=64 {
            for v in 0u64..=8 {
                let candidate = topology.leader_index_prf(seed, h, v);
                if candidate != 0 {
                    height = h;
                    view = v;
                    leader = candidate;
                    break 'search;
                }
            }
        }
    }
    assert_ne!(leader, 0, "test requires non-zero PRF leader index");

    let rotated = super::topology_for_view(&topology, height, view, super::NPOS_TAG, Some(seed));
    let expected = topology.as_ref().get(leader).expect("leader peer exists");
    assert_eq!(rotated.as_ref().first(), Some(expected));
}

#[test]
fn topology_for_view_canonicalizes_npos_roster_order() {
    let kp_a = KeyPair::from_seed(vec![0xA1; 32], Algorithm::BlsNormal);
    let kp_b = KeyPair::from_seed(vec![0xB2; 32], Algorithm::BlsNormal);
    let kp_c = KeyPair::from_seed(vec![0xC3; 32], Algorithm::BlsNormal);
    let kp_d = KeyPair::from_seed(vec![0xD4; 32], Algorithm::BlsNormal);
    let mut canonical = vec![
        PeerId::new(kp_a.public_key().clone()),
        PeerId::new(kp_b.public_key().clone()),
        PeerId::new(kp_c.public_key().clone()),
        PeerId::new(kp_d.public_key().clone()),
    ];
    canonical.sort();
    let topology = super::network_topology::Topology::new(canonical.clone());
    let mut scrambled = canonical.clone();
    scrambled.rotate_left(1);
    let scrambled_topology = super::network_topology::Topology::new(scrambled);

    let seed = [0x44_u8; 32];
    let mut height = 1u64;
    let mut view = 0u64;
    let mut leader = topology.leader_index_prf(seed, height, view);
    if leader == 0 {
        'search: for h in 1u64..=64 {
            for v in 0u64..=8 {
                let candidate = topology.leader_index_prf(seed, h, v);
                if candidate != 0 {
                    height = h;
                    view = v;
                    leader = candidate;
                    break 'search;
                }
            }
        }
    }
    assert_ne!(leader, 0, "test requires non-zero PRF leader index");

    let rotated = super::topology_for_view(&topology, height, view, super::NPOS_TAG, Some(seed));
    let rotated_scrambled = super::topology_for_view(
        &scrambled_topology,
        height,
        view,
        super::NPOS_TAG,
        Some(seed),
    );
    assert_eq!(rotated.as_ref(), rotated_scrambled.as_ref());
}

