#[test]
fn validate_block_for_voting_records_timings() {
    let world = World::default();
    let kura = Arc::new(Kura::blank_kura_for_testing());
    let query = LiveQueryStore::start_test();
    let state = State::new_for_testing(world, Arc::clone(&kura), query);
    let chain: ChainId = "vote-validation-timings".parse().expect("chain id parses");
    let kp = KeyPair::random_with_algorithm(Algorithm::BlsNormal);
    let peer = PeerId::new(kp.public_key().clone());
    let mut topology = super::network_topology::Topology::new(vec![peer]);
    let genesis_account = SAMPLE_GENESIS_ACCOUNT_ID.clone();
    let mut voting_block = None;

    let genesis_hash = seed_genesis_block_for_state(&state);
    let block_ok = heartbeat_block_for_state(&state, &chain, 2, 0, Some(genesis_hash), &kp, 0);
    let (result_ok, timings_ok) = super::validate_block_for_voting_with_timings(
        block_ok,
        &mut topology,
        &chain,
        &genesis_account,
        &state,
        &mut voting_block,
    );
    assert!(result_ok.is_ok(), "expected valid block to pass validation");
    assert!(
        timings_ok.total_ms >= timings_ok.stateless_ms,
        "total timing must cover stateless stage"
    );
    assert!(
        timings_ok.total_ms >= timings_ok.execution_ms,
        "total timing must cover execution stage"
    );
    let stateless_detail_ms = timings_ok
        .stateless_state_dependent_ms
        .saturating_add(timings_ok.stateless_snapshot_ms);
    assert!(
        timings_ok.stateless_ms >= stateless_detail_ms,
        "stateless timing must cover stateless sub-stages"
    );
    let execution_tx_detail_ms = timings_ok
        .execution_tx_signature_batch_ms
        .saturating_add(timings_ok.execution_tx_stateless_ms)
        .saturating_add(timings_ok.execution_tx_access_ms)
        .saturating_add(timings_ok.execution_tx_overlay_ms)
        .saturating_add(timings_ok.execution_tx_dag_ms)
        .saturating_add(timings_ok.execution_tx_schedule_ms)
        .saturating_add(timings_ok.execution_tx_apply_ms);
    assert!(
        timings_ok.execution_tx_ms >= execution_tx_detail_ms,
        "execution tx timing must cover tx sub-stages"
    );
    let execution_tx_apply_detail_ms = timings_ok
        .execution_tx_apply_prep_ms
        .saturating_add(timings_ok.execution_tx_apply_detached_ms)
        .saturating_add(timings_ok.execution_tx_apply_merge_ms)
        .saturating_add(timings_ok.execution_tx_apply_fallback_ms)
        .saturating_add(timings_ok.execution_tx_apply_quarantine_ms)
        .saturating_add(timings_ok.execution_tx_apply_sequential_ms)
        .saturating_add(timings_ok.execution_tx_time_triggers_ms)
        .saturating_add(timings_ok.execution_tx_finalize_ms);
    assert!(
        timings_ok.execution_tx_apply_ms >= execution_tx_apply_detail_ms,
        "execution tx apply timing must cover apply sub-stages"
    );
    let execution_detail_ms = timings_ok
        .execution_da_indexes_ms
        .saturating_add(timings_ok.execution_state_block_ms)
        .saturating_add(timings_ok.execution_tx_ms)
        .saturating_add(timings_ok.execution_axt_ms)
        .saturating_add(timings_ok.execution_da_cursor_ms)
        .saturating_add(timings_ok.execution_genesis_clean_ms);
    assert!(
        timings_ok.execution_ms >= execution_detail_ms,
        "execution timing must cover execution sub-stages"
    );

    voting_block = None;
    let block_bad = heartbeat_block_for_state(&state, &chain, 2, 0, None, &kp, 0);
    let (_result_bad, timings_bad) = super::validate_block_for_voting_with_timings(
        block_bad,
        &mut topology,
        &chain,
        &genesis_account,
        &state,
        &mut voting_block,
    );
    assert_eq!(
        timings_bad.execution_ms, 0,
        "stateless failures should not record execution time"
    );
    let execution_bad_tx_detail_ms = timings_bad
        .execution_tx_signature_batch_ms
        .saturating_add(timings_bad.execution_tx_stateless_ms)
        .saturating_add(timings_bad.execution_tx_access_ms)
        .saturating_add(timings_bad.execution_tx_overlay_ms)
        .saturating_add(timings_bad.execution_tx_dag_ms)
        .saturating_add(timings_bad.execution_tx_schedule_ms)
        .saturating_add(timings_bad.execution_tx_apply_ms);
    let execution_bad_apply_detail_ms = timings_bad
        .execution_tx_apply_prep_ms
        .saturating_add(timings_bad.execution_tx_apply_detached_ms)
        .saturating_add(timings_bad.execution_tx_apply_merge_ms)
        .saturating_add(timings_bad.execution_tx_apply_fallback_ms)
        .saturating_add(timings_bad.execution_tx_apply_quarantine_ms)
        .saturating_add(timings_bad.execution_tx_apply_sequential_ms)
        .saturating_add(timings_bad.execution_tx_time_triggers_ms)
        .saturating_add(timings_bad.execution_tx_finalize_ms);
    let execution_bad_detail_ms = timings_bad
        .execution_da_indexes_ms
        .saturating_add(timings_bad.execution_state_block_ms)
        .saturating_add(timings_bad.execution_tx_ms)
        .saturating_add(timings_bad.execution_axt_ms)
        .saturating_add(timings_bad.execution_da_cursor_ms)
        .saturating_add(timings_bad.execution_genesis_clean_ms);
    assert_eq!(
        execution_bad_detail_ms, 0,
        "stateless failures should not record execution sub-stages"
    );
    assert_eq!(
        execution_bad_tx_detail_ms, 0,
        "stateless failures should not record execution tx sub-stages"
    );
    assert_eq!(
        execution_bad_apply_detail_ms, 0,
        "stateless failures should not record execution tx apply sub-stages"
    );
}

#[test]
fn exec_roots_capture_fallback_uses_witness_snapshot() {
    let _guard = crate::sumeragi::witness::exec_witness_guard();
    let world = World::default();
    let kura = Arc::new(Kura::blank_kura_for_testing());
    let query = LiveQueryStore::start_test();
    let state = State::new_for_testing(world, Arc::clone(&kura), query);

    let genesis_hash = seed_genesis_block_for_state(&state);
    let header = BlockHeader::new(nonzero!(2_u64), Some(genesis_hash), None, None, 0, 0);
    let block_hash = header.hash();
    let mut state_block = state.block(header);

    crate::sumeragi::witness::start_block();
    let asset_def: AssetDefinitionId = "rose#wonderland"
        .parse()
        .expect("asset definition id parses");
    let asset_id = AssetId::new(asset_def, (*ALICE_ID).clone());
    let pre = iroha_primitives::numeric::Numeric::from(1u32);
    let post = iroha_primitives::numeric::Numeric::from(2u32);
    crate::sumeragi::witness::record_read_asset(&asset_id, Some(&pre));
    crate::sumeragi::witness::record_write_asset(&asset_id, &post);

    let expected = crate::sumeragi::witness::snapshot_exec_witness();
    let expected_parent = parent_state_from_witness(&expected);
    let expected_post = post_state_from_witness(&expected);

    let roots = exec_roots_for_state_block(&mut state_block, block_hash, 2, 0).expect("roots");
    assert_eq!(roots.parent_state_root, expected_parent);
    assert_eq!(roots.post_state_root, expected_post);
}

#[test]
fn validation_reject_reason_label_covers_error_categories() {
    let reason_prev_hash =
        super::validation_reject_reason_label(&BlockValidationError::PrevBlockHashMismatch {
            expected: None,
            actual: None,
        });
    assert_eq!(reason_prev_hash, super::VALIDATION_REASON_PREV_HASH);

    let reason_prev_height =
        super::validation_reject_reason_label(&BlockValidationError::PrevBlockHeightMismatch {
            expected: 2,
            actual: 1,
        });
    assert_eq!(reason_prev_height, super::VALIDATION_REASON_PREV_HEIGHT);

    let reason_topology =
        super::validation_reject_reason_label(&BlockValidationError::TopologyMismatch {
            expected: Vec::new(),
            actual: Vec::new(),
        });
    assert_eq!(reason_topology, super::VALIDATION_REASON_TOPOLOGY);

    let reason_execution = super::validation_reject_reason_label(
        &BlockValidationError::TransactionAccept(AcceptTransactionFail::TransactionExpired {
            expires_at_ms: 10,
            now_ms: 20,
        }),
    );
    assert_eq!(reason_execution, super::VALIDATION_REASON_EXECUTION);

    let reason_duplicate =
        super::validation_reject_reason_label(&BlockValidationError::DuplicateTransactions);
    assert_eq!(reason_duplicate, super::VALIDATION_REASON_EXECUTION);

    let reason_stateless = super::validation_reject_reason_label(
        &BlockValidationError::InvalidGenesis(crate::block::InvalidGenesisError::InvalidSignature),
    );
    assert_eq!(reason_stateless, super::VALIDATION_REASON_STATELESS);
}

