#[test]
fn build_consensus_proposal_populates_defaults() {
    let block = empty_block(5, 0, None);
    let payload_hash = Hash::new(b"payload-bytes");
    let subject_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x42; 32]));
    let qc_ref = QcHeaderRef {
        height: 4,
        view: 1,
        epoch: 0,
        subject_block_hash: subject_hash,
        phase: crate::sumeragi::consensus::Phase::Prepare,
    };
    let proposal_epoch = 7;

    let proposal = Actor::build_consensus_proposal(
        &block,
        payload_hash,
        qc_ref,
        3,
        /*view*/ 2,
        proposal_epoch,
    );

    let zero_hash = Hash::prehashed([0; Hash::LENGTH]);
    let expected_parent = HashOf::<BlockHeader>::from_untyped_unchecked(zero_hash);

    assert_eq!(proposal.payload_hash, payload_hash);
    assert_eq!(proposal.header.height, block.header().height().get());
    assert_eq!(proposal.header.view, 2);
    assert_eq!(proposal.header.proposer, 3);
    assert_eq!(proposal.header.epoch, proposal_epoch);
    assert_eq!(proposal.header.parent_hash, expected_parent);
    assert_eq!(proposal.header.tx_root, zero_hash);
    assert_eq!(proposal.header.state_root, zero_hash);
    assert_eq!(proposal.header.highest_qc, qc_ref);
}

#[test]
fn commit_quorum_timeout_tracks_block_time() {
    let block_time = Duration::from_millis(1_000);
    let mut commit_time = Duration::from_millis(150);
    let mut da_enabled = true;
    let mut quorum_multiplier =
        iroha_config::parameters::defaults::sumeragi::DA_QUORUM_TIMEOUT_MULTIPLIER;

    assert_eq!(
        super::commit_quorum_timeout_from_durations(
            block_time,
            commit_time,
            da_enabled,
            quorum_multiplier
        ),
        Duration::from_millis(4_800)
    );
    quorum_multiplier = 1;
    assert_eq!(
        super::commit_quorum_timeout_from_durations(
            block_time,
            commit_time,
            da_enabled,
            quorum_multiplier
        ),
        Duration::from_millis(1_600)
    );
    quorum_multiplier = iroha_config::parameters::defaults::sumeragi::DA_QUORUM_TIMEOUT_MULTIPLIER;

    commit_time = Duration::from_millis(2_500);
    assert_eq!(
        super::commit_quorum_timeout_from_durations(
            block_time,
            commit_time,
            da_enabled,
            quorum_multiplier
        ),
        Duration::from_millis(33_000)
    );

    commit_time = Duration::ZERO;
    assert_eq!(
        super::commit_quorum_timeout_from_durations(
            block_time,
            commit_time,
            da_enabled,
            quorum_multiplier
        ),
        Duration::from_millis(1_000),
        "zero commit timeout should fall back to block_time for liveness"
    );

    da_enabled = false;
    commit_time = Duration::from_millis(150);
    assert_eq!(
        super::commit_quorum_timeout_from_durations(
            block_time,
            commit_time,
            da_enabled,
            quorum_multiplier
        ),
        Duration::from_millis(2_000)
    );

    commit_time = Duration::from_millis(2_500);
    assert_eq!(
        super::commit_quorum_timeout_from_durations(
            block_time,
            commit_time,
            da_enabled,
            quorum_multiplier
        ),
        Duration::from_millis(2_500)
    );

    commit_time = Duration::ZERO;
    assert_eq!(
        super::commit_quorum_timeout_from_durations(
            block_time,
            commit_time,
            da_enabled,
            quorum_multiplier
        ),
        Duration::from_millis(1_000),
        "zero commit timeout should fall back to block_time for liveness"
    );
}

