#[tokio::test(flavor = "current_thread")]
async fn stale_view_accepts_rbc_messages_with_da() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;
    consensus_cfg.rbc.chunk_max_bytes = 1024;
    consensus_cfg.rbc.pending_max_chunks = 10;
    consensus_cfg.rbc.pending_max_bytes = 4096;
    let mut harness = test_actor_harness_with_config(4, consensus_cfg, None).await;
    let actor = &mut harness.actor;
    let height = 7;
    let local_view = 3;
    let stale_view = 2;
    let now = Instant::now();
    actor.phase_tracker.start_new_round(height, now);
    actor.phase_tracker.on_view_change(height, local_view, now);

    let block_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x22; 32]));
    let payload_hash = Hash::prehashed([0x33; 32]);
    let chunk_root = Hash::prehashed([0x44; 32]);
    let key = (block_hash, height, stale_view);
    let roster = actor.effective_commit_topology();
    let (block_header, leader_signature) =
        rbc_header_and_signature(actor, &roster, height, stale_view, &harness.key_pairs);

    let init = crate::sumeragi::consensus::RbcInit {
        block_hash,
        height,
        view: stale_view,
        epoch: 0,
        roster: roster.clone(),
        roster_hash: roster_hash(&roster),
        total_chunks: 1,
        chunk_digests: vec![[0x44; 32]],
        payload_hash,
        chunk_root,
        block_header,
        leader_signature,
    };
    actor.handle_rbc_init(init, None).expect("rbc init");
    assert!(actor.subsystems.da_rbc.rbc.sessions.contains_key(&key));

    let chunk = crate::sumeragi::consensus::RbcChunk {
        block_hash,
        height,
        view: stale_view,
        epoch: 0,
        idx: 0,
        bytes: vec![0x01],
    };
    actor.handle_rbc_chunk(chunk, None).expect("rbc chunk");
    assert!(actor.subsystems.da_rbc.rbc.pending.is_empty());

    let session = RbcSession::test_new(1, Some(payload_hash), Some(chunk_root), 0);
    actor.subsystems.da_rbc.rbc.sessions.insert(key, session);

    let session = actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .cloned()
        .expect("session");
    let ready = actor.build_rbc_ready(key, &session).expect("ready");
    actor.handle_rbc_ready(ready).expect("rbc ready");
    let stored = actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .expect("session");
    assert!(
        !stored.ready_signatures.is_empty(),
        "stale-view READY should be accepted for known sessions"
    );

    let session = actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .cloned()
        .expect("session");
    let deliver = actor.build_rbc_deliver(key, &session).expect("deliver");
    actor.handle_rbc_deliver(deliver).expect("rbc deliver");
    let stored = actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .get(&key)
        .expect("session");
    assert!(
        !stored.delivered,
        "stale-view DELIVER without quorum should remain deferred"
    );
    assert!(
        actor.subsystems.da_rbc.rbc.pending.contains_key(&key),
        "stale-view DELIVER should be queued for known sessions"
    );

    harness.shutdown.send();
}

