#[tokio::test(flavor = "current_thread")]
async fn pending_rbc_slot_eviction_releases_block_payload_dedup() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;
    actor.config.rbc.pending_ttl = Duration::from_millis(1);

    let key = pending_session_key(10);
    let epoch = actor.epoch_for_height(key.1);
    let roster_hash = Hash::prehashed([0x22; Hash::LENGTH]);
    let chunk_root = Hash::prehashed([0x33; Hash::LENGTH]);
    let ready = crate::sumeragi::consensus::RbcReady {
        block_hash: key.0,
        height: key.1,
        view: key.2,
        epoch,
        roster_hash,
        chunk_root,
        sender: 0,
        signature: vec![0xAA],
    };
    let deliver = crate::sumeragi::consensus::RbcDeliver {
        block_hash: key.0,
        height: key.1,
        view: key.2,
        epoch,
        roster_hash,
        chunk_root,
        sender: 0,
        signature: vec![0xBB],
        ready_signatures: Vec::new(),
    };
    let chunk = crate::sumeragi::consensus::RbcChunk {
        block_hash: key.0,
        height: key.1,
        view: key.2,
        epoch,
        idx: 0,
        bytes: vec![0x10, 0x20],
    };

    let mut pending = PendingRbcMessages::new(Instant::now() - Duration::from_millis(10));
    let max_bytes = 16 * 1024;
    let max_chunks = 4;
    assert!(
        pending
            .push_ready_capped(ready.clone(), max_bytes, Instant::now())
            .0
    );
    assert!(
        pending
            .push_deliver_capped(deliver.clone(), max_bytes, Instant::now())
            .0
    );
    let _ = pending.push_chunk_capped(chunk.clone(), None, max_chunks, max_bytes, Instant::now());
    assert_eq!(pending.pending_chunks(), 1);

    let ready_key = crate::sumeragi::BlockPayloadDedupKey::RbcReady {
        height: ready.height,
        view: ready.view,
        block_hash: ready.block_hash,
        sender: ready.sender,
        signature_hash: Hash::new(&ready.signature),
    };
    let deliver_key = crate::sumeragi::BlockPayloadDedupKey::RbcDeliver {
        height: deliver.height,
        view: deliver.view,
        block_hash: deliver.block_hash,
        sender: deliver.sender,
        signature_hash: Hash::new(&deliver.signature),
    };
    let chunk_key = crate::sumeragi::BlockPayloadDedupKey::RbcChunk {
        height: chunk.height,
        view: chunk.view,
        epoch: chunk.epoch,
        block_hash: chunk.block_hash,
        idx: chunk.idx,
        bytes_hash: Hash::new(&chunk.bytes),
    };
    {
        let mut guard = actor
            .block_payload_dedup
            .lock()
            .expect("block payload dedup cache poisoned");
        guard.insert(ready_key, Instant::now());
        guard.insert(deliver_key, Instant::now());
        guard.insert(chunk_key, Instant::now());
    }

    actor.subsystems.da_rbc.rbc.pending.insert(key, pending);
    let _ = actor.pending_rbc_slot(pending_session_key(11));

    let guard = actor
        .block_payload_dedup
        .lock()
        .expect("block payload dedup cache poisoned");
    assert!(!guard.contains(&ready_key));
    assert!(!guard.contains(&deliver_key));
    assert!(!guard.contains(&chunk_key));

    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn rbc_drop_releases_block_payload_dedup_on_session_limit() {
    let mut harness = test_actor_harness(1).await;
    let actor = &mut harness.actor;
    actor.config.rbc.pending_session_limit = 1;

    let active_key = session_key();
    let epoch = actor.epoch_for_height(active_key.1);
    actor
        .subsystems
        .da_rbc
        .rbc
        .sessions
        .insert(active_key, RbcSession::test_new(1, None, None, epoch));
    actor
        .subsystems
        .da_rbc
        .rbc
        .pending
        .insert(active_key, PendingRbcMessages::new(Instant::now()));

    let drop_key = (
        HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x44; Hash::LENGTH])),
        active_key.1,
        active_key.2.saturating_add(1),
    );
    let epoch = actor.epoch_for_height(drop_key.1);
    let roster_hash = Hash::prehashed([0x55; Hash::LENGTH]);
    let chunk_root = Hash::prehashed([0x66; Hash::LENGTH]);

    let ready = crate::sumeragi::consensus::RbcReady {
        block_hash: drop_key.0,
        height: drop_key.1,
        view: drop_key.2,
        epoch,
        roster_hash,
        chunk_root,
        sender: 0,
        signature: vec![0x01],
    };
    let ready_key = crate::sumeragi::BlockPayloadDedupKey::RbcReady {
        height: ready.height,
        view: ready.view,
        block_hash: ready.block_hash,
        sender: ready.sender,
        signature_hash: Hash::new(&ready.signature),
    };
    {
        let mut guard = actor
            .block_payload_dedup
            .lock()
            .expect("block payload dedup cache poisoned");
        guard.insert(ready_key, Instant::now());
    }
    actor.handle_rbc_ready(ready).expect("ready handled");
    assert!(
        !actor
            .block_payload_dedup
            .lock()
            .expect("block payload dedup cache poisoned")
            .contains(&ready_key)
    );

    let deliver = crate::sumeragi::consensus::RbcDeliver {
        block_hash: drop_key.0,
        height: drop_key.1,
        view: drop_key.2,
        epoch,
        roster_hash,
        chunk_root,
        sender: 0,
        signature: vec![0x02],
        ready_signatures: Vec::new(),
    };
    let deliver_key = crate::sumeragi::BlockPayloadDedupKey::RbcDeliver {
        height: deliver.height,
        view: deliver.view,
        block_hash: deliver.block_hash,
        sender: deliver.sender,
        signature_hash: Hash::new(&deliver.signature),
    };
    {
        let mut guard = actor
            .block_payload_dedup
            .lock()
            .expect("block payload dedup cache poisoned");
        guard.insert(deliver_key, Instant::now());
    }
    actor.handle_rbc_deliver(deliver).expect("deliver handled");
    assert!(
        !actor
            .block_payload_dedup
            .lock()
            .expect("block payload dedup cache poisoned")
            .contains(&deliver_key)
    );

    let chunk = crate::sumeragi::consensus::RbcChunk {
        block_hash: drop_key.0,
        height: drop_key.1,
        view: drop_key.2,
        epoch,
        idx: 0,
        bytes: vec![0x03, 0x04],
    };
    let chunk_key = crate::sumeragi::BlockPayloadDedupKey::RbcChunk {
        height: chunk.height,
        view: chunk.view,
        epoch: chunk.epoch,
        block_hash: chunk.block_hash,
        idx: chunk.idx,
        bytes_hash: Hash::new(&chunk.bytes),
    };
    {
        let mut guard = actor
            .block_payload_dedup
            .lock()
            .expect("block payload dedup cache poisoned");
        guard.insert(chunk_key, Instant::now());
    }
    actor.handle_rbc_chunk(chunk, None).expect("chunk handled");
    assert!(
        !actor
            .block_payload_dedup
            .lock()
            .expect("block payload dedup cache poisoned")
            .contains(&chunk_key)
    );

    harness.shutdown.send();
}

#[test]
fn commitment_snapshot_builder_converts_totals() {
    let mut lane_totals = BTreeMap::new();
    lane_totals.insert(LaneId::new(3), (7, 9, 512, 400));
    let mut dataspace_totals = BTreeMap::new();
    dataspace_totals.insert((LaneId::new(3), DataSpaceId::new(11)), (4, 6, 256, 128));
    let block_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xCC; 32]));
    let height = 21;

    let (lane_commitments, dataspace_commitments) = super::build_commitment_snapshots_from_totals(
        lane_totals,
        dataspace_totals,
        block_hash,
        height,
    );

    assert_eq!(lane_commitments.len(), 1);
    let lane = lane_commitments[0];
    assert_eq!(lane.block_height, height);
    assert_eq!(lane.lane_id, 3);
    assert_eq!(lane.tx_count, 7);
    assert_eq!(lane.total_chunks, 9);
    assert_eq!(lane.rbc_bytes_total, 512);
    assert_eq!(lane.teu_total, 400);
    assert_eq!(lane.block_hash, block_hash);

    assert_eq!(dataspace_commitments.len(), 1);
    let dataspace = dataspace_commitments[0];
    assert_eq!(dataspace.block_height, height);
    assert_eq!(dataspace.lane_id, 3);
    assert_eq!(dataspace.dataspace_id, 11);
    assert_eq!(dataspace.tx_count, 4);
    assert_eq!(dataspace.total_chunks, 6);
    assert_eq!(dataspace.rbc_bytes_total, 256);
    assert_eq!(dataspace.teu_total, 128);
    assert_eq!(dataspace.block_hash, block_hash);
}

#[test]
fn rbc_session_adopts_persisted_allocations() {
    let mut session = RbcSession::test_new(4, None, None, 0);
    assert!(session.lane_allocations.is_empty());
    let summary = rbc_status::Summary {
        block_hash: HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0x55; 32])),
        height: 5,
        view: 0,
        total_chunks: 4,
        received_chunks: 2,
        ready_count: 1,
        delivered: false,
        payload_hash: None,
        recovered_from_disk: true,
        invalid: false,
        lane_backlog: vec![status::LaneRbcSnapshot {
            lane_id: 7,
            tx_count: 3,
            total_chunks: 4,
            pending_chunks: 2,
            rbc_bytes_total: 1024,
        }],
        dataspace_backlog: vec![status::DataspaceRbcSnapshot {
            lane_id: 7,
            dataspace_id: 42,
            tx_count: 3,
            total_chunks: 4,
            pending_chunks: 2,
            rbc_bytes_total: 1024,
        }],
    };

    session.adopt_allocations_from_summary(&summary);
    assert_eq!(session.lane_allocations.len(), 1);
    assert_eq!(session.dataspace_allocations.len(), 1);
    assert_eq!(session.lane_allocations[0].lane_id, LaneId::new(7));
    assert_eq!(
        session.dataspace_allocations[0].dataspace_id,
        DataSpaceId::new(42)
    );

    let mut session_again = session.clone();
    session_again.adopt_allocations_from_summary(&summary);
    assert_eq!(session_again.lane_allocations.len(), 1);
    assert_eq!(session_again.dataspace_allocations.len(), 1);
}

#[test]
fn rbc_session_new_rejects_chunk_over_cap() {
    let too_many = super::RBC_MAX_TOTAL_CHUNKS + 1;
    let err = RbcSession::new(too_many, None, None, None, 0)
        .expect_err("session should reject chunk overflow");
    match err {
        super::RbcSessionError::TooManyChunks {
            total_chunks,
            max_chunks,
        } => {
            assert_eq!(total_chunks, too_many);
            assert_eq!(max_chunks, super::RBC_MAX_TOTAL_CHUNKS);
        }
        other => panic!("unexpected error: {other:?}"),
    }
}

#[test]
fn rbc_session_new_rejects_digest_count_mismatch() {
    let err = RbcSession::new(2, None, None, Some(vec![[0u8; 32]]), 0)
        .expect_err("session should reject digest count mismatch");
    match err {
        super::RbcSessionError::DigestCountMismatch {
            total_chunks,
            observed,
        } => {
            assert_eq!(total_chunks, 2);
            assert_eq!(observed, 1);
        }
        other => panic!("unexpected error: {other:?}"),
    }
}

#[test]
fn backpressure_gate_defers_when_saturated() {
    let capacity = NonZeroUsize::new(4).expect("non-zero");
    let (tx, rx) = watch::channel(BackpressureState::Healthy {
        queued: 0,
        capacity,
    });
    let mut gate = super::BackpressureGate::new(rx);
    assert!(!gate.should_defer());

    tx.send(BackpressureState::Saturated {
        queued: 4,
        capacity,
    })
    .expect("send saturated");
    assert!(gate.should_defer());

    tx.send(BackpressureState::Healthy {
        queued: 2,
        capacity,
    })
    .expect("send healthy");
    assert!(!gate.should_defer());
}

#[test]
fn backpressure_gate_refresh_reports_changes() {
    let capacity = NonZeroUsize::new(2).expect("non-zero");
    let (tx, rx) = watch::channel(BackpressureState::Healthy {
        queued: 0,
        capacity,
    });
    let mut gate = super::BackpressureGate::new(rx);

    // Initial refresh should be a no-op because the snapshot is unchanged.
    assert!(!gate.refresh());
    assert_eq!(
        gate.state(),
        BackpressureState::Healthy {
            queued: 0,
            capacity
        }
    );

    tx.send(BackpressureState::Saturated {
        queued: capacity.get(),
        capacity,
    })
    .expect("send saturated");

    // A changed snapshot should be observed once and cached for subsequent reads.
    assert!(gate.refresh());
    assert_eq!(
        gate.state(),
        BackpressureState::Saturated {
            queued: capacity.get(),
            capacity
        }
    );
    assert!(
        !gate.refresh(),
        "refresh should be false when the state has not changed again"
    );
}

#[test]
fn pacemaker_respects_refreshed_backpressure_state() {
    let capacity = NonZeroUsize::new(3).expect("non-zero");
    let (tx, rx) = watch::channel(BackpressureState::Healthy {
        queued: 0,
        capacity,
    });
    let mut gate = super::BackpressureGate::new(rx);
    let start = Instant::now();
    let mut pacemaker = super::Pacemaker::with_interval(Duration::from_millis(5), start);
    let mut tracker = super::PacemakerBackpressure::new();

    // Backpressure flips to saturated after the initial snapshot; refreshing via should_defer
    // must propagate to the pacemaker evaluation.
    tx.send(BackpressureState::Saturated {
        queued: capacity.get(),
        capacity,
    })
    .expect("send saturated");

    let should_defer = gate.should_defer();
    let state = gate.state();
    let backpressure = ProposalBackpressure {
        queue_state: state,
        active_pending: false,
        rbc_backlog: false,
        relay_backpressure: false,
        consensus_queue_backpressure: false,
    };
    let (log_first, log_fire, attempt) =
        Actor::evaluate_pacemaker(&mut pacemaker, &mut tracker, backpressure, start);

    assert!(should_defer, "gate should report saturation");
    assert!(state.is_saturated(), "state snapshot must reflect refresh");
    assert!(log_first, "first saturation should be logged");
    assert!(
        log_fire,
        "deferral logging should be requested under saturation"
    );
    assert!(
        !attempt,
        "pacemaker should not attempt before the deadline while saturated"
    );
}

#[test]
fn evaluate_pacemaker_continues_under_saturation() {
    let capacity = NonZeroUsize::new(4).expect("non-zero");
    let state = BackpressureState::Saturated {
        queued: 4,
        capacity,
    };
    let backpressure = ProposalBackpressure {
        queue_state: state,
        active_pending: false,
        rbc_backlog: false,
        relay_backpressure: false,
        consensus_queue_backpressure: false,
    };
    let now = Instant::now();
    let mut pacemaker = super::Pacemaker::with_interval(Duration::from_millis(5), now);
    let mut tracker = super::PacemakerBackpressure::new();

    let (log_first, log_fire, should_attempt) =
        Actor::evaluate_pacemaker(&mut pacemaker, &mut tracker, backpressure, now);

    assert!(
        !should_attempt,
        "pacemaker should defer proposal while saturated before the deadline"
    );
    assert!(log_first, "initial saturation should trigger deferral log");
    assert!(
        log_fire,
        "saturation should request deferral logging when deferring"
    );
}

#[test]
fn evaluate_pacemaker_defers_and_recovers_after_backoff() {
    let capacity = NonZeroUsize::new(3).expect("non-zero");
    let saturated = BackpressureState::Saturated {
        queued: 3,
        capacity,
    };
    let saturated_backpressure = ProposalBackpressure {
        queue_state: saturated,
        active_pending: false,
        rbc_backlog: false,
        relay_backpressure: false,
        consensus_queue_backpressure: false,
    };
    let start = Instant::now();
    let mut pacemaker = super::Pacemaker::with_interval(Duration::from_millis(5), start);
    let mut tracker = super::PacemakerBackpressure::new();

    // First firing while saturated should defer and log.
    let (log_first, log_fire, attempt) =
        Actor::evaluate_pacemaker(&mut pacemaker, &mut tracker, saturated_backpressure, start);
    assert!(log_first, "first saturation should be logged");
    assert!(log_fire, "saturation must request deferral logging");
    assert!(
        !attempt,
        "proposal assembly should be deferred while saturated"
    );

    // Within the same window nothing should fire again.
    let (log_repeat, log_fire_repeat, attempt_repeat) = Actor::evaluate_pacemaker(
        &mut pacemaker,
        &mut tracker,
        saturated_backpressure,
        start + Duration::from_millis(2),
    );
    assert!(!log_repeat);
    assert!(!log_fire_repeat);
    assert!(!attempt_repeat);

    // Once saturation clears after the deadline passes, pacemaker should resume.
    let healthy = BackpressureState::Healthy {
        queued: 0,
        capacity,
    };
    let healthy_backpressure = ProposalBackpressure {
        queue_state: healthy,
        active_pending: false,
        rbc_backlog: false,
        relay_backpressure: false,
        consensus_queue_backpressure: false,
    };
    let (log_recovered, log_fire_recovered, attempt_recovered) = Actor::evaluate_pacemaker(
        &mut pacemaker,
        &mut tracker,
        healthy_backpressure,
        start + Duration::from_millis(6),
    );
    assert!(!log_recovered);
    assert!(!log_fire_recovered);
    assert!(
        attempt_recovered,
        "pacemaker should attempt once backpressure clears"
    );
}

#[test]
fn evaluate_pacemaker_fires_after_deadline_even_when_saturated() {
    let capacity = NonZeroUsize::new(2).expect("non-zero");
    let saturated = BackpressureState::Saturated {
        queued: 2,
        capacity,
    };
    let backpressure = ProposalBackpressure {
        queue_state: saturated,
        active_pending: false,
        rbc_backlog: false,
        relay_backpressure: false,
        consensus_queue_backpressure: false,
    };
    let start = Instant::now();
    let mut pacemaker = super::Pacemaker::with_interval(Duration::from_millis(5), start);
    let mut tracker = super::PacemakerBackpressure::new();

    // After the deadline elapses, the pacemaker should attempt even if saturation persists.
    let (log_first, log_fire, attempt) = Actor::evaluate_pacemaker(
        &mut pacemaker,
        &mut tracker,
        backpressure,
        start + Duration::from_millis(6),
    );

    assert!(log_first, "first saturation window should be logged");
    assert!(
        log_fire,
        "deadline-fired attempt should be logged under saturation"
    );
    assert!(
        attempt,
        "pacemaker should still attempt to propose after the deadline while saturated"
    );
}

#[test]
fn evaluate_pacemaker_defers_for_non_queue_backpressure() {
    let capacity = NonZeroUsize::new(2).expect("non-zero");
    let healthy = BackpressureState::Healthy {
        queued: 0,
        capacity,
    };
    let start = Instant::now();
    let mut pacemaker = super::Pacemaker::with_interval(Duration::from_millis(5), start);
    let mut tracker = super::PacemakerBackpressure::new();

    // Non-queue backpressure should keep proposals deferred even after the deadline.
    let backpressure = ProposalBackpressure {
        queue_state: healthy,
        active_pending: false,
        rbc_backlog: true,
        relay_backpressure: false,
        consensus_queue_backpressure: false,
    };
    let (log_first, log_fire, attempt) =
        Actor::evaluate_pacemaker(&mut pacemaker, &mut tracker, backpressure, start);
    assert!(log_first, "first deferral should be logged");
    assert!(!log_fire, "no deadline deferral log before the fire");
    assert!(
        !attempt,
        "pacemaker should not attempt before the deadline under non-queue backpressure"
    );

    let (log_after, log_fire_after, attempt_after) = Actor::evaluate_pacemaker(
        &mut pacemaker,
        &mut tracker,
        backpressure,
        start + Duration::from_millis(6),
    );
    assert!(!log_after);
    assert!(
        log_fire_after,
        "deadline deferral should request logging under non-queue backpressure"
    );
    assert!(
        !attempt_after,
        "pacemaker should not attempt after the deadline under non-queue backpressure"
    );
}

