fn pending_rbc_chunk_eviction_records_drop_counts() {
    let now = Instant::now();
    let mut pending = PendingRbcMessages::new(now);
    let chunk_a = sample_chunk_with_len(0, 4);
    let chunk_b = sample_chunk_with_len(1, 6);

    match pending.push_chunk_capped(chunk_a, None, 1, 8, now) {
        PendingChunkOutcome::Inserted {
            pending_chunks,
            evicted_chunks,
            ..
        } => {
            assert_eq!(pending_chunks, 1);
            assert_eq!(evicted_chunks, 0);
        }
        other => panic!("unexpected outcome: {other:?}"),
    }

    match pending.push_chunk_capped(chunk_b, None, 1, 8, now) {
        PendingChunkOutcome::Inserted {
            pending_chunks,
            pending_bytes,
            evicted_chunks,
            evicted_bytes,
        } => {
            assert_eq!(pending_chunks, 1);
            assert_eq!(pending_bytes, 6);
            assert_eq!(evicted_chunks, 1);
            assert_eq!(evicted_bytes, 4);
        }
        other => panic!("unexpected outcome: {other:?}"),
    }

    let (dropped_chunks, dropped_bytes) = pending.dropped_counts();
    assert_eq!(dropped_chunks, 1);
    assert_eq!(dropped_bytes, 4);
}

#[test]
fn pending_rbc_snapshot_includes_entry_drop_counts() {
    super::status::reset_pending_rbc_for_tests();
    let now = Instant::now();
    let block_hash = HashOf::<BlockHeader>::from_untyped_unchecked(Hash::prehashed([0xDA; 32]));
    let key: SessionKey = (block_hash, 7, 0);
    let chunk = crate::sumeragi::consensus::RbcChunk {
        block_hash,
        height: key.1,
        view: key.2,
        epoch: 0,
        idx: 0,
        bytes: vec![1, 2, 3, 4],
    };

    let mut pending_entry = PendingRbcMessages::new(now);
    let _ = pending_entry.push_chunk_capped(chunk, None, 0, 0, now);
    let mut pending = BTreeMap::new();
    pending.insert(key, pending_entry);

    Actor::update_rbc_backlog_snapshot(
        &BTreeMap::new(),
        &pending,
        (1, 4),
        Duration::from_secs(1),
        16,
        None,
    );

    let snapshot = super::status::pending_rbc_snapshot();
    assert_eq!(snapshot.entries.len(), 1);
    let entry = &snapshot.entries[0];
    assert_eq!(entry.dropped_chunks, 1);
    assert_eq!(entry.dropped_bytes, 4);
    assert_eq!(entry.ready, 0);
    assert_eq!(entry.deliver, 0);

    super::status::reset_pending_rbc_for_tests();
}

#[test]
fn pending_rbc_ttl_counts_from_last_seen() {
    let created = Instant::now();
    let mut pending = PendingRbcMessages::new(created);
    let touched = created + Duration::from_millis(50);
    pending.touch(touched);

    assert!(
        !pending.expired(Duration::from_millis(10), touched),
        "TTL should be measured from the most recent pending frame"
    );
    assert!(
        pending.expired(
            Duration::from_millis(10),
            touched + Duration::from_millis(11)
        ),
        "pending entry should expire after the last activity window"
    );
}

#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_runs_with_backlog_when_commit_qc_ready() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;

    let mut harness = test_actor_harness_with_config_and_height(1, consensus_cfg, None, 1).await;
    let actor = &mut harness.actor;
    super::status::reset_worker_loop_snapshot_for_tests();

    let (height, tip_hash) = {
        let view = actor.state.view();
        (
            u64::try_from(view.height()).unwrap_or(0).saturating_add(1),
            view.latest_block_hash(),
        )
    };
    let block = sample_block(height, 0, tip_hash);
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let mut pending = PendingBlock::new(block.clone(), payload_hash, height, 0);

    // Satisfy commit QC ready conditions.
    pending.commit_qc_seen = true;
    pending.validation_status = ValidationStatus::Valid;
    pending.parent_state_root = Some(zero_state_root());
    pending.post_state_root = Some(zero_state_root());
    // payload_available check: local payload matches (from sample_block construction)

    let block_hash = pending.block.hash();
    actor.pending.pending_blocks.insert(block_hash, pending);

    actor.pending.last_commit_pipeline_run = Instant::now() - Duration::from_secs(10);
    let last_run = actor.pending.last_commit_pipeline_run;

    // Simulate backlog.
    super::status::record_worker_queue_enqueue(super::status::WorkerQueueKind::Votes);
    assert!(super::status::worker_queue_depth_snapshot().vote_rx > 0);

    // Provide a dummy lock QC to allow commit
    actor.locked_qc = Some(sample_qc_ref(1, 0));

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Event, None);

    assert!(
        actor.pending.last_commit_pipeline_run > last_run,
        "commit pipeline should run with backlog when a tip-extending commit QC is ready"
    );

    super::status::reset_worker_loop_snapshot_for_tests();
    harness.shutdown.send();
}

#[tokio::test(flavor = "current_thread")]
async fn commit_pipeline_runs_with_backlog_without_commit_qc() {
    let mut consensus_cfg = test_sumeragi_config();
    consensus_cfg.consensus_mode = ConsensusMode::Permissioned;
    consensus_cfg.da.enabled = true;

    let mut harness = test_actor_harness_with_config_and_height(1, consensus_cfg, None, 1).await;
    let actor = &mut harness.actor;
    super::status::reset_worker_loop_snapshot_for_tests();

    let (height, tip_hash) = {
        let view = actor.state.view();
        (
            u64::try_from(view.height()).unwrap_or(0).saturating_add(1),
            view.latest_block_hash(),
        )
    };
    let block = sample_block(height, 0, tip_hash);
    let payload_hash = Hash::new(super::proposals::block_payload_bytes(&block));
    let mut pending = PendingBlock::new(block.clone(), payload_hash, height, 0);

    // No commit QC yet.
    pending.commit_qc_seen = false;
    pending.validation_status = ValidationStatus::Valid;
    pending.parent_state_root = Some(zero_state_root());
    pending.post_state_root = Some(zero_state_root());

    let block_hash = pending.block.hash();
    actor.pending.pending_blocks.insert(block_hash, pending);

    actor.pending.last_commit_pipeline_run = Instant::now() - Duration::from_secs(10);
    let last_run = actor.pending.last_commit_pipeline_run;

    // Simulate backlog.
    super::status::record_worker_queue_enqueue(super::status::WorkerQueueKind::Votes);
    assert!(super::status::worker_queue_depth_snapshot().vote_rx > 0);

    // Provide a dummy lock QC
    actor.locked_qc = Some(sample_qc_ref(1, 0));

    actor.process_commit_candidates_with_trigger(CommitPipelineTrigger::Event, None);

    assert!(
        actor.pending.last_commit_pipeline_run > last_run,
        "commit pipeline should run with backlog even when no commit QC is available"
    );
    assert!(
        actor.pending.pending_blocks.contains_key(&block_hash),
        "pending block should remain when no commit QC is available"
    );

    super::status::reset_worker_loop_snapshot_for_tests();
    harness.shutdown.send();
}
